function mapToCanonicalClaim(raw) {
  return {
    claim_id: raw.claim_id || raw.id || raw.claim_number || "",
    payer: raw.payer_name || raw.payer || "",
    billed_amount: Number(raw.billed_amount ?? raw.billed ?? 0),
    paid_amount: Number(raw.paid_amount ?? raw.paid ?? 0),
    status: raw.status || "Pending",
    dos: raw.dos || "",
    source: raw.source || "integration"
  };
}

function mapToCanonicalClaims(org_id, rows) {
  const incoming = Array.isArray(rows) ? rows.map(mapToCanonicalClaim) : [];
  if (!incoming.length) return;

  const billed = readJSON(FILES.billed, []);
  const orgClaims = billed.filter(b => b.org_id === org_id);

  for (const c of incoming) {
    if (!c.claim_id) continue;

    const match = orgClaims.find(x =>
      String(x.claim_id || x.claim_number || x.billed_id || "") === String(c.claim_id)
    );

    if (match) {
      if (c.payer) match.payer = c.payer;
      if (Number.isFinite(c.billed_amount)) match.billed_amount = c.billed_amount;
      if (Number.isFinite(c.paid_amount)) match.paid_amount = c.paid_amount;
      if (c.status) match.status = c.status;
      if (c.dos) match.dos = c.dos;
      match.last_sync_at = nowISO();
      match.updated_at = nowISO();
    } else {
      billed.push({
        billed_id: uuid(),
        org_id,
        claim_id: c.claim_id,
        claim_number: c.claim_id,
        payer: c.payer || "",
        billed_amount: Number.isFinite(c.billed_amount) ? c.billed_amount : 0,
        paid_amount: Number.isFinite(c.paid_amount) ? c.paid_amount : 0,
        status: c.status || "Pending",
        dos: c.dos || "",
        source: c.source || "integration",
        created_at: nowISO(),
        updated_at: nowISO(),
        last_sync_at: nowISO()
      });
    }
  }

  writeJSON(FILES.billed, billed);
}

function derivePaidStatusForClaim(claim, paidAmount) {
  const billedAmt = Number(claim?.billed_amount || 0);
  const expectedAmt = Number(claim?.expected_amount || 0);

  if (paidAmount <= 0) return "Denied";
  if (expectedAmt > 0 && paidAmount < expectedAmt) return "Underpaid";
  if (billedAmt > 0 && paidAmount < billedAmt && expectedAmt <= 0) return "Partial Payment";
  return "Paid";
}

function scorePaymentMatch(claim, payment) {
  let score = 0;

  const claimId = String(claim.claim_id || claim.claim_number || "").toLowerCase();
  const paymentId = String(payment.claim_id || "").toLowerCase();

  const payerA = String(claim.payer || "").toLowerCase();
  const payerB = String(payment.payer || "").toLowerCase();

  const billed = Number(claim.billed_amount || 0);
  const expected = Number(claim.expected_amount || 0);
  const paid = Number(payment.paid_amount || 0);

  if (claimId && paymentId && claimId === paymentId) score += 70;

  if (expected > 0) {
    const diff = Math.abs(expected - paid);
    const pct = diff / expected;

    if (pct < 0.02) score += 25;
    else if (pct < 0.1) score += 15;
    else if (pct < 0.25) score += 5;
  } else if (billed > 0) {
    const diff = Math.abs(billed - paid);
    const pct = diff / billed;

    if (pct < 0.02) score += 20;
    else if (pct < 0.1) score += 10;
  }

  if (payerA && payerB && payerA === payerB) score += 10;

  return Math.min(score, 100);
}

function findBestClaimMatch(org_id, payment) {
  const claims = readJSON(FILES.billed, [])
    .filter(c => c.org_id === org_id);

  let best = null;

  for (const claim of claims) {
    const score = scorePaymentMatch(claim, payment);

    if (!best || score > best.score) {
      best = {
        claim,
        score
      };
    }
  }

  return best;
}

const AUTO_MATCH_THRESHOLD = 90;

function attemptAutoMatch(org_id, payment) {
  const bestMatch = findBestClaimMatch(org_id, payment);

  if (!bestMatch || bestMatch.score < AUTO_MATCH_THRESHOLD) {
    return {
      autoMatched: false,
      reason: "low_confidence",
      score: bestMatch?.score || 0
    };
  }

  const claim = bestMatch.claim;

  const result = applyPaymentToClaim(org_id, {
    claim_id: claim.claim_id || claim.claim_number || claim.billed_id,
    paid_amount: payment.paid_amount,
    payer: payment.payer,
    billed_amount: payment.billed_amount,
    source: "auto_match"
  });

  return {
    autoMatched: true,
    score: bestMatch.score,
    claim_id: claim.claim_id || claim.claim_number,
    result
  };
}

// ==============================
// ACTION CENTER TASK ENGINE
// ==============================
function getTasksForOrg(org_id) {
  return readJSON(FILES.agent_tasks, []).filter(t => t.org_id === org_id);
}

function saveTasks(tasks) {
  writeJSON(FILES.agent_tasks, tasks);
}

// prevent duplicates (same claim + same task type still open)
function findOpenTask(tasks, org_id, billed_id, type) {
  return tasks.find(t =>
    t.org_id === org_id &&
    t.billed_id === billed_id &&
    t.type === type &&
    ["queued", "open", "in_progress"].includes(String(t.status || ""))
  );
}

function createActionTask(org_id, claim, type, meta = {}) {
  const tasks = getTasksForOrg(org_id);

  const exists = findOpenTask(tasks, org_id, claim.billed_id, type);
  if (exists) return exists; // no duplicates

  const task = {
    task_id: uuid(),
    org_id,
    billed_id: claim.billed_id,
    claim_id: claim.claim_id || claim.claim_number || "",
    payer: claim.payer || "",
    type, // "appeal" | "negotiation" | "follow_up"
    status: "queued",
    priority: Number(claim.__risk || claim.risk_score || 50),
    at_risk_amount: Number(claim.at_risk_amount || 0),
    next_action: meta.next_action || "",
    source: meta.source || "system_auto",
    created_at: nowISO(),
    updated_at: nowISO()
  };

  const allTasks = readJSON(FILES.agent_tasks, []);
  allTasks.push(task);
  saveTasks(allTasks);
  return task;
}

function autoCreateTasksFromStatus(org_id, claim) {
  const status = String(claim.status || "").toLowerCase();

  if (status === "underpaid") {
    createActionTask(org_id, claim, "negotiation", {
      next_action: "Initiate negotiation for underpayment"
    });
  }

  if (status === "denied") {
    createActionTask(org_id, claim, "appeal", {
      next_action: "Prepare and submit appeal"
    });
  }

  if (status === "waiting payment") {
    const days = claim.dos
      ? Math.floor((Date.now() - new Date(claim.dos).getTime()) / (1000 * 60 * 60 * 24))
      : 0;

    if (days > 30) {
      createActionTask(org_id, claim, "follow_up", {
        next_action: "Follow up with payer (no payment >30 days)"
      });
    }
  }
}

// ==============================
// AUTO PACKET CREATION ENGINE
// ==============================

function findExistingPacket(org_id, billed_id, type) {
  const packets = readJSON(PACKET_FILE, []);
  return packets.find(p =>
    p.org_id === org_id &&
    p.billed_id === billed_id &&
    p.type === type &&
    p.status !== "closed"
  );
}

function createPacketForClaim(org_id, claim, type) {
  const existing = findExistingPacket(org_id, claim.billed_id, type);
  if (existing) return existing; // 🚫 prevent duplicates

  const packet = {
    packet_id: uuid(),
    org_id,
    billed_id: claim.billed_id,
    claim_id: claim.claim_id || claim.claim_number,
    payer: claim.payer || "",
    type, // "appeal" | "negotiation"
    status: "draft",
    created_at: nowISO(),
    updated_at: nowISO(),

    data: {
      claim_number: claim.claim_number || "",
      dos: claim.dos || "",
      billed_amount: claim.billed_amount || 0,
      paid_amount: claim.paid_amount || 0,
      expected_amount: claim.expected_amount || 0
    }
  };

  return savePacket(packet);
}

// ==============================
// LINK PACKET TO TASK
// ==============================

function attachPacketToTask(org_id, claim, taskType) {
  const tasks = readJSON(FILES.agent_tasks, []);

  const task = tasks.find(t =>
    t.org_id === org_id &&
    t.billed_id === claim.billed_id &&
    t.type === taskType &&
    ["queued","open","in_progress"].includes(String(t.status || ""))
  );

  if (!task) return null;

  // already linked
  if (task.packet_id) return task;

  let packetType = null;

  if (taskType === "appeal") packetType = "appeal";
  if (taskType === "negotiation") packetType = "negotiation";

  if (!packetType) return task;

  const packet = createPacketForClaim(org_id, claim, packetType);

  task.packet_id = packet.packet_id;
  task.updated_at = nowISO();

  writeJSON(FILES.agent_tasks, tasks);

  return task;
}

// ==============================
// LIFECYCLE → TASK → PACKET LINK
// ==============================

function autoLinkPacketFromStatus(org_id, claim) {
  const status = String(claim.status || "").toLowerCase();

  if (status === "underpaid") {
    attachPacketToTask(org_id, claim, "negotiation");
  }

  if (status === "denied") {
    attachPacketToTask(org_id, claim, "appeal");
  }
}

// ======================================================
// PACKET AUTO-FILL + WORKSPACE LINK + SAFE ROUTING (NO AUTO SEND)
// ======================================================

// ---------- OPTIONAL EHR DOCUMENT HOOK (safe placeholder) ----------
function fetchEHRDocuments(org_id, claim){
  // 🔒 SAFE: return empty until you wire real EHR
  // Later: pull via FHIR DocumentReference/Binary
  return {
    denial_letter: null,
    eob: null,
    claim_form: null,
    medical_records: [],
    labs: []
  };
}

// ---------- AUTO-FILL PACKET CONTENT ----------
function buildPacketContent(org_id, claim, type){
  const ehr = fetchEHRDocuments(org_id, claim);

  const underpaid = Math.max(0,
    Number(claim.expected_amount || 0) - Number(claim.paid_amount || 0)
  );

  const narrative = `
Re: Claim #${claim.claim_number || claim.claim_id}
Payer: ${claim.payer || ""}
DOS: ${claim.dos || "N/A"}

This ${type} is submitted for reconsideration of the above claim.

Summary:
- Billed: $${Number(claim.billed_amount || 0).toFixed(2)}
- Expected: $${Number(claim.expected_amount || 0).toFixed(2)}
- Paid: $${Number(claim.paid_amount || 0).toFixed(2)}
- At Risk: $${underpaid.toFixed(2)}

Requested Action:
- Reprocess claim per benefits/contract
- Apply correct reimbursement
- Provide written rationale if denial remains
`;

  return {
    financial_summary: {
      billed: claim.billed_amount || 0,
      expected: claim.expected_amount || 0,
      paid: claim.paid_amount || 0,
      underpaid
    },
    narrative,
    attachments: {
      denial_letter: ehr.denial_letter,
      eob: ehr.eob,
      claim_form: ehr.claim_form,
      medical_records: ehr.medical_records,
      labs: ehr.labs
    },
    completeness: {
      has_denial_letter: !!ehr.denial_letter,
      has_eob: !!ehr.eob,
      has_claim_form: !!ehr.claim_form
    }
  };
}

// ---------- ROUTING (PREP ONLY — NO SEND) ----------
function determinePacketRoute(payer){
  const p = String(payer || "").toLowerCase();

  if (p.includes("medicare")) return "esmd";
  if (p.includes("uhc") || p.includes("united")) return "optum_api";
  if (p.includes("aetna") || p.includes("cigna")) return "availity";

  return "manual";
}

// ---------- CREATE OR UPDATE PACKET WITH CONTENT ----------
function enrichPacketWithContent(org_id, packet, claim){
  const content = buildPacketContent(org_id, claim, packet.type);

  packet.content = content;

  // 👇 READY FOR REVIEW (NOT SENT)
  packet.status = "ready_for_review";
  packet.route = determinePacketRoute(packet.payer);

  packet.updated_at = nowISO();

  savePacket(packet);
  return packet;
}

// ---------- TASK → WORKSPACE LINK ----------
function getWorkspaceUrl(packet_id){
  return `/packet/workspace?packet_id=${encodeURIComponent(packet_id)}`;
}

function attachWorkspaceToTask(task){
  if (!task.packet_id) return task;

  task.workspace_url = getWorkspaceUrl(task.packet_id);
  task.updated_at = nowISO();
  return task;
}

// ---------- LIFECYCLE EXTENSION (MAIN ENTRY POINT) ----------
function autoPreparePacketFromStatus(org_id, claim){
  const status = String(claim.status || "").toLowerCase();

  let packetType = null;
  let taskType = null;

  if (status === "underpaid"){
    packetType = "negotiation";
    taskType = "negotiation";
  }

  if (status === "denied"){
    packetType = "appeal";
    taskType = "appeal";
  }

  if (!packetType) return;

  // 1. Ensure task exists (you already do this elsewhere)
  // 2. Find or create packet
  const packet = createPacketForClaim(org_id, claim, packetType);

  // 3. Enrich packet with data (AUTO-FILL)
  const enriched = enrichPacketWithContent(org_id, packet, claim);

  // 4. Attach to task
  const tasks = readJSON(FILES.agent_tasks, []);
  const task = tasks.find(t =>
    t.org_id === org_id &&
    t.billed_id === claim.billed_id &&
    t.type === taskType &&
    ["queued","open","in_progress"].includes(String(t.status || ""))
  );

  if (task){
    task.packet_id = enriched.packet_id;
    attachWorkspaceToTask(task);
    writeJSON(FILES.agent_tasks, tasks);
  }
}

// ======================================================
// PACKET SUBMISSION + CHECKLIST + FHIR EHR PULL (SAFE)
// ======================================================

// ---------- CHECKLIST (can be overridden) ----------
function getPacketChecklist(packet){
  const c = packet.content || {};
  const a = (c.attachments || {});
  return {
    has_eob: !!a.eob,
    has_denial_letter: !!a.denial_letter,
    has_claim_form: !!a.claim_form,
    // you can add payer-specific rules later
    ready:
      !!a.eob && (!!a.denial_letter || packet.type === "negotiation")
  };
}

