// bundle all generated exports into one zip-like manifest download fallback
// MVP safe approach: generate a single bundle.json that lists all export URLs
function exportPacketBundle(packet){
  packet.exports = packet.exports || {};

  const bundle = {
    packet_id: packet.packet_id,
    generated_at: nowISO(),
    files: {
      printable_html: packet.exports.printable_html || null,
      manifest_json: packet.exports.manifest_json || null,
      edi_275_stub: packet.exports.edi_275_stub || null
    }
  };

  const bundlePath = packetExportPath(packet.packet_id, "bundle.json");
  fs.writeFileSync(bundlePath, JSON.stringify(bundle, null, 2), "utf8");

  packet.exports.bundle_json = `/data/packet_exports/${packet.packet_id}.bundle.json`;
  packet.updated_at = nowISO();
  savePacket(packet);

  return {
    type: "bundle_json",
    path: bundlePath,
    url: packet.exports.bundle_json
  };
}

function regeneratePacketArtifacts(packet){
  exportPacketPrintable(packet);
  exportPacketManifest(packet);
  exportPacket275Stub(packet);
  exportPacketBundle(packet);

  packet.updated_at = nowISO();
  savePacket(packet);
  return packet;
}

function getSubmissionStatusMeta(packet){
  const submission = packet.submission || {};
  const status = String(packet.status || "").toLowerCase();

  if (status === "error") {
    return {
      label: "Error",
      color: "#dc2626"
    };
  }

  if (submission.prepared_only) {
    return {
      label: "Prepared Only",
      color: "#f59e0b"
    };
  }

  if (status === "submitted" || status === "accepted") {
    return {
      label: "Submitted",
      color: "#16a34a"
    };
  }

  return {
    label: packet.status || "Draft",
    color: "#6b7280"
  };
}

// ------------------------------
// ADAPTERS
// NOTE: real HTTP calls only if credentials + endpoint configured.
// Otherwise returns "prepared_not_sent" safely.
// ------------------------------
async function sendViaAvaility(org_id, packet){
  const creds = await getIntegrationCredentialsForRoute(org_id, "availity");
  const bundle = await buildOutboundPacketBundle(org_id, packet);

  if (!creds || !creds.base_url || !(creds.api_key || creds.token || creds.client_id)) {
    return {
      ok: true,
      prepared_only: true,
      channel: "availity_api",
      external_id: "AV-PREP-" + Date.now(),
      message: "Availity adapter prepared, credentials/endpoints incomplete"
    };
  }

  // Real call scaffold
  // Replace endpoint + payload shape with actual Availity attachment endpoint contract
  const headers = {
    "Content-Type": "application/json",
    ...(creds.token ? { "Authorization": `Bearer ${creds.token}` } : {}),
    ...(creds.api_key ? { "x-api-key": creds.api_key } : {})
  };

  const payload = {
    packet_id: packet.packet_id,
    claim_id: packet.claim_id,
    payer: packet.payer,
    packet_type: packet.type,
    manifest_url: bundle.manifest.url,
    printable_url: bundle.printable.url,
    edi_275_url: bundle.edi275.url
  };

  const response = await fetch(`${String(creds.base_url).replace(/\/+$/,"")}/attachments`, {
    method: "POST",
    headers,
    body: JSON.stringify(payload)
  }).then(async (r) => ({
    ok: r.ok,
    status: r.status,
    body: await r.text()
  }));

  return {
    ok: !!response.ok,
    prepared_only: false,
    channel: "availity_api",
    external_id: "AV-" + Date.now(),
    response_status: response.status
  };
}

