// ---------- VERIFY WEBHOOK (basic security) ----------
function verifyWebhook(req, expectedKey){
  const key = req.headers["x-webhook-key"] || "";
  return String(key) === String(expectedKey || process.env.WEBHOOK_SECRET || "dev_secret");
}

// ---------- GENERIC WEBHOOK HANDLER ----------
async function handleIncomingWebhook(body){
  // Expected payload shape (flexible):
  // {
  //   packet_id,
  //   external_id,
  //   status: "accepted" | "rejected"
  // }

  const data = typeof body === "string" ? JSON.parse(body || "{}") : (body || {});
  const { packet_id, external_id, status } = data;

  if (!packet_id && !external_id){
    return { ok: false, error: "missing identifiers" };
  }

  const packets = readJSON(PACKET_FILE, []);

  let packet = null;

  if (packet_id){
    packet = packets.find(p => p.packet_id === packet_id);
  }

  if (!packet && external_id){
    packet = packets.find(p =>
      p.submission && String(p.submission.external_id) === String(external_id)
    );
  }

  if (!packet){
    return { ok: false, error: "packet not found" };
  }

  const org_id = packet.org_id;

  // 🔥 CORE HOOK (you already built this earlier)
  handleExternalSubmissionUpdate(org_id, packet.packet_id, status);

  return { ok: true };
}

// ---------- MOCK STATUS CHECK (replace with real APIs later) ----------
async function checkExternalStatus(packet){
  const submission = packet.submission || {};

  // If no external ID → nothing to check
  if (!submission.external_id) return null;

  // 🔒 SAFE: mock behavior for now
  // Later: call Availity / Optum APIs here

  const rand = Math.random();

  if (rand < 0.05) return "accepted";  // 5% simulate success
  if (rand < 0.10) return "rejected";  // 5% simulate rejection

  return null; // still pending
}

// ---------- POLLING WORKER ----------
async function pollPacketStatuses(){
  const packets = readJSON(PACKET_FILE, []);

  for (const packet of packets){

    // only check submitted packets
    if (!packet || packet.status !== PACKET_STATES.SUBMITTED) continue;

    try {
      const status = await checkExternalStatus(packet);

      if (!status) continue;

      // 🔥 reuse same system as webhook
      handleExternalSubmissionUpdate(packet.org_id, packet.packet_id, status);

      console.log("Packet updated via polling:", packet.packet_id, status);

    } catch (e){
      console.error("Polling error:", packet.packet_id, e?.message || e);
    }
  }
}

function applyPaymentToClaim(org_id, payment) {
  const canonical = {
    claim_id: payment.claim_id || payment.claim_number || "",
    paid_amount: Number(payment.paid_amount || 0),
    payer: payment.payer || payment.payer_name || "",
    billed_amount: Number(payment.billed_amount || 0),
    source: payment.source || "835"
  };

  const billed = readJSON(FILES.billed, []);
  const unmatched = readJSON(FILES.unmatched_payments, []);

  const claim = billed.find(b =>
    b.org_id === org_id &&
    String(b.claim_id || b.claim_number || b.billed_id || "") === String(canonical.claim_id)
  );

  if (!claim) {
    const auto = attemptAutoMatch(org_id, canonical);

    if (auto.autoMatched) {
      return {
        matched: true,
        autoMatched: true,
        score: auto.score,
        claim_id: auto.claim_id
      };
    }

    unmatched.push({
      unmatched_id: uuid(),
      org_id,
      claim_id: canonical.claim_id,
      payer: canonical.payer,
      billed_amount: canonical.billed_amount,
      paid_amount: canonical.paid_amount,
      source: canonical.source,
      status: "unmatched",
      auto_match_score: auto.score,
      created_at: nowISO()
    });

    writeJSON(FILES.unmatched_payments, unmatched);

    return {
      matched: false,
      reason: "claim_not_found",
      auto_match_score: auto.score
    };
  }

  const expected = Number(claim.expected_amount || 0);
  const paid = Number(canonical.paid_amount || 0);

  let newStatus = "Paid";

  if (paid <= 0) {
    newStatus = "Denied";
  } else if (expected > 0 && paid < expected) {
    newStatus = "Underpaid";
  } else if (claim.billed_amount > 0 && paid < claim.billed_amount && expected === 0) {
    newStatus = "Partial Payment";
  } else {
    newStatus = "Paid";
  }

  const priorPaid = Number(claim.paid_amount || 0);

  claim.payer = canonical.payer || claim.payer || "";
  claim.paid_amount = paid;
  claim.status = newStatus;
  // AUTO CREATE TASKS
  autoCreateTasksFromStatus(org_id, claim);
  // 🔥 AUTO LINK PACKET
  autoLinkPacketFromStatus(org_id, claim);
  // 🔥 AUTO PREP PACKET (FILLED + ROUTED + READY FOR REVIEW)
  autoPreparePacketFromStatus(org_id, claim);
  if (newStatus === "Paid") {
    closeTasksForClaim(org_id, claim.billed_id);
  }
  claim.last_payment_sync_at = nowISO();
  claim.updated_at = nowISO();
  claim.payment_source = canonical.source;

  claim.payment_debug = {
    expected_amount: expected,
    paid_amount: paid,
    previous_paid_amount: priorPaid,
    decision: newStatus
  };

  const payments = readJSON(FILES.payments, []);
  payments.push({
    payment_id: uuid(),
    org_id,
    billed_id: claim.billed_id,
    claim_id: claim.claim_id || claim.claim_number || "",
    payer: canonical.payer || claim.payer || "",
    paid_amount: paid,
    previous_paid_amount: priorPaid,
    expected_amount: expected,
    status: newStatus,
    source: canonical.source,
    imported_at: nowISO()
  });

  writeJSON(FILES.billed, billed);
  writeJSON(FILES.payments, payments);

  return {
    matched: true,
    billed_id: claim.billed_id,
    claim_id: claim.claim_id || claim.claim_number || "",
    paid_amount: paid,
    expected_amount: expected,
    status: newStatus
  };
}
function updateClaimStatus(org_id, statusUpdate) {
  const canonical = mapToCanonicalClaim(statusUpdate);
  const billed = readJSON(FILES.billed, []);
  const claim = billed.find(b =>
    b.org_id === org_id &&
    String(b.claim_id || b.claim_number || b.billed_id || "") === String(canonical.claim_id || "")
  );

  if (!claim) return { matched: false, reason: "claim_not_found", claim_id: canonical.claim_id };

  claim.status = canonical.status || claim.status || "Pending";
  claim.last_status_sync_at = nowISO();
  claim.updated_at = nowISO();
  claim.status_source = canonical.source || "integration";

  writeJSON(FILES.billed, billed);

  return {
    matched: true,
    billed_id: claim.billed_id,
    claim_id: claim.claim_id || claim.claim_number || "",
    status: claim.status
  };
}

function normalizeEdiText(input) {
  if (Buffer.isBuffer(input)) return input.toString("utf8");
  if (typeof input === "string") return input;
  if (input && typeof input.text === "string") return input.text;
  return "";
}

function parse835(input) {
  const text = normalizeEdiText(input).trim();
  if (!text) return [];

  const normalized = text
    .replace(/\r\n/g, "")
    .replace(/\n/g, "")
    .replace(/\r/g, "");

  const rawSegments = normalized
    .split("~")
    .map(s => s.trim())
    .filter(Boolean);

  let currentPayer = "";
  const payments = [];

  for (let idx = 0; idx < rawSegments.length; idx++) {
    const seg = rawSegments[idx];
    const parts = seg.split("*");
    const tag = parts[0];

    if (tag === "N1" && String(parts[1] || "").toUpperCase() === "PR") {
      currentPayer = parts[2] || currentPayer || "";
    }

    if (tag === "CLP") {
      const claimId = String(parts[1] || "").trim();
      const statusCode = String(parts[2] || "").trim();
      const totalCharge = Number(parts[3] || 0);
      const paidAmount = Number(parts[4] || 0);

      let mappedStatus = "Paid";
      if (statusCode === "4") mappedStatus = "Denied";
      else if (paidAmount <= 0) mappedStatus = "Denied";
      else if (paidAmount > 0 && totalCharge > 0 && paidAmount < totalCharge) mappedStatus = "Partial Payment";

      payments.push({
        claim_id: claimId,
        payer: currentPayer,
        billed_amount: totalCharge,
        paid_amount: paidAmount,
        status: mappedStatus,
        source: "835"
      });
    }
  }

  return payments;
}

function parse277(input) {
  const text = normalizeEdiText(input).trim();
  if (!text) return [];

  const normalized = text
    .replace(/\r\n/g, "")
    .replace(/\n/g, "")
    .replace(/\r/g, "");

  const rawSegments = normalized
    .split("~")
    .map(s => s.trim())
    .filter(Boolean);

  const updates = [];
  let currentClaimId = "";

  for (const seg of rawSegments) {
    const parts = seg.split("*");
    const tag = parts[0];

    if (tag === "TRN") {
      currentClaimId = String(parts[2] || parts[1] || "").trim();
    }

    if (tag === "STC" && currentClaimId) {
      const composite = String(parts[1] || "");
      const category = composite.split(":")[0] || "";
      let mappedStatus = "Pending";

      if (category === "F2" || category === "A3") mappedStatus = "Denied";
      else if (category === "A1") mappedStatus = "Submitted";
      else if (category === "A2") mappedStatus = "In Process";
      else if (category === "P3") mappedStatus = "Paid";

      updates.push({
        claim_id: currentClaimId,
        status: mappedStatus,
        source: "277"
      });
    }
  }

  return updates;
}

