function orgPacketContext(orgLike) {
  const org = normalizeOrgProfile(typeof orgLike === "object" ? orgLike : { org_name: String(orgLike || "") });
  const displayName = org.legal_name || org.dba_name || org.org_name || "";
  const mailingSame = org.mailing_same_as_physical;
  const mailingAddr = mailingSame
    ? [org.address_line1, org.address_line2, `${org.city}, ${org.state} ${org.zip}`, org.country].filter(Boolean).join(", ")
    : [org.mailing_address_line1, org.mailing_address_line2, `${org.mailing_city}, ${org.mailing_state} ${org.mailing_zip}`, org.country].filter(Boolean).join(", ");
  return {
    displayName,
    legalName: org.legal_name,
    taxId: org.tax_id,
    npi: org.npi_number,
    npiType: org.npi_type,
    taxonomyCode: org.taxonomy_code,
    stateLicenseNumber: org.state_license_number,
    physicalAddress: [org.address_line1, org.address_line2, `${org.city}, ${org.state} ${org.zip}`, org.country].filter(Boolean).join(", "),
    mailingAddress: mailingAddr,
    mainPhone: org.main_phone,
    fax: org.fax,
    billingPhone: org.billing_phone,
    billingEmail: org.billing_email,
    website: org.website,
    repName: org.rep_name,
    repTitle: org.rep_title,
    repPhone: org.rep_phone,
    repEmail: org.rep_email,
  };
}

function parseCookies(req) {
  const header = req.headers.cookie || "";
  const out = {};
  header.split(";").map(x => x.trim()).filter(Boolean).forEach(pair => {
    const idx = pair.indexOf("=");
    if (idx > -1) out[pair.slice(0, idx)] = decodeURIComponent(pair.slice(idx+1));
  });
  return out;
}

/**
 * FIX: Railway-safe cookies.
 * In production browsers require Secure for SameSite=None; but you use SameSite=Lax.
 * Still, "Secure" should only be set when behind HTTPS.
 */
function setCookie(res, name, value, maxAgeSeconds) {
  const parts = [
    `${name}=${encodeURIComponent(value)}`,
    "Path=/",
    "SameSite=Lax",
    "HttpOnly",
  ];
  if (IS_PROD) parts.push("Secure");
  if (maxAgeSeconds) parts.push(`Max-Age=${maxAgeSeconds}`);

  // allow multiple cookies in the same response
  const cookieStr = parts.join("; ");
  const prev = res.getHeader("Set-Cookie");
  if (!prev) res.setHeader("Set-Cookie", [cookieStr]);
  else if (Array.isArray(prev)) res.setHeader("Set-Cookie", prev.concat(cookieStr));
  else res.setHeader("Set-Cookie", [String(prev), cookieStr]);
}

function clearCookie(res, name) {
  const cookieStr = `${name}=; Path=/; Max-Age=0; SameSite=Lax; HttpOnly${IS_PROD ? "; Secure" : ""}`;
  const prev = res.getHeader("Set-Cookie");
  if (!prev) res.setHeader("Set-Cookie", [cookieStr]);
  else if (Array.isArray(prev)) res.setHeader("Set-Cookie", prev.concat(cookieStr));
  else res.setHeader("Set-Cookie", [String(prev), cookieStr]);
}

function send(res, status, body, type="text/html") {
  res.writeHead(status, { "Content-Type": type });
  res.end(body);
}

function redirect(res, location) {
  const existingHeaders = res.getHeaders ? res.getHeaders() : {};
  res.writeHead(302, {
    ...existingHeaders,
    Location: location
  });
  res.end();
}

function parseBody(req) {
  return new Promise(resolve => {
    let body = "";
    req.on("data", c => body += c);
    req.on("end", () => resolve(body));
  });
}

function parseRawBody(req) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    req.on("data", chunk => chunks.push(chunk));
    req.on("end", () => resolve(Buffer.concat(chunks)));
    req.on("error", reject);
  });
}

// ===== Session =====
function hmacSign(value, secret) {
  return crypto.createHmac("sha256", secret).update(value).digest("hex");
}
function makeSession(payload) {
  const json = JSON.stringify(payload);
  const b64 = Buffer.from(json).toString("base64url");
  const sig = hmacSign(b64, SESSION_SECRET);
  return `${b64}.${sig}`;
}
function verifySession(token) {
  if (!token || !token.includes(".")) return null;
  const [b64, sig] = token.split(".");
  const expected = hmacSign(b64, SESSION_SECRET);
  if (sig !== expected) return null;
  try {
    const json = Buffer.from(b64, "base64url").toString("utf8");
    const payload = JSON.parse(json);
    if (!payload.exp || Date.now() > payload.exp) return null;
    return payload;
  } catch { return null; }
}
// Split sessions so admin + user can stay logged in in the same browser
const USER_SESSION_COOKIE = "tjhp_session";
const ADMIN_SESSION_COOKIE = "tjhp_admin_session";

function getAuthUser(req) {
  const cookies = parseCookies(req);
  const sess = verifySession(cookies[USER_SESSION_COOKIE]);
  // Legacy safety: older builds stored admin sessions in the user cookie.
  if (sess && sess.role === "admin") return null;
  return sess;
}

function getAuthAdmin(req) {
  const cookies = parseCookies(req);
  const sess = verifySession(cookies[ADMIN_SESSION_COOKIE]);
  if (sess) return sess;
  // Legacy fallback: allow admin sessions that were stored in tjhp_session.
  const legacy = verifySession(cookies[USER_SESSION_COOKIE]);
  return (legacy && legacy.role === "admin") ? legacy : null;
}

function getAuth(req) {
  let pathname = "";
  try { pathname = new URL(req.url, "http://localhost").pathname; } catch { pathname = ""; }

  const userSess = getAuthUser(req);
  const adminSess = getAuthAdmin(req);

  // Prefer owner/admin cookie on /admin routes, user cookie everywhere else.
  if (pathname.startsWith("/admin")) return adminSess || userSess;
  return userSess || adminSess;
}
function isSimulationSession(sess) {
  return !!(sess && (sess.simulation === true || String(sess.org_id || "").startsWith("sim_")));
}
function setSession(res, payload) {
  const token = makeSession(payload);
  setCookie(res, USER_SESSION_COOKIE, token, SESSION_TTL_DAYS * 86400);
}

function setAdminSession(res, payload) {
  const token = makeSession(payload);
  setCookie(res, ADMIN_SESSION_COOKIE, token, SESSION_TTL_DAYS * 86400);
}

