// ===== Models helpers =====
function getOrg(org_id) {
  return readJSON(FILES.orgs, []).find(o => o.org_id === org_id);
}

function getAnalyticsStore() {
  return readJSON(FILES.analytics, {
    leads: 0,
    signups: 0,
    revenue: 0,
    subscriptions: {
      starter: 0,
      growth: 0,
      pro: 0,
      enterprise: 0
    }
  });
}
function saveAnalyticsStore(store) {
  const subscriptions = {
    starter: Number(store?.subscriptions?.starter || 0),
    growth: Number(store?.subscriptions?.growth || 0),
    pro: Number(store?.subscriptions?.pro || 0),
    enterprise: Number(store?.subscriptions?.enterprise || 0),
  };
  writeJSON(FILES.analytics, {
    leads: Number(store?.leads || 0),
    signups: Number(store?.signups || 0),
    revenue: Number(store?.revenue || 0),
    subscriptions,
  });
}
function trackAnalyticsLead() {
  const analytics = getAnalyticsStore();
  analytics.leads = Number(analytics.leads || 0) + 1;
  saveAnalyticsStore(analytics);
}
function trackAnalyticsSignup() {
  const analytics = getAnalyticsStore();
  analytics.signups = Number(analytics.signups || 0) + 1;
  saveAnalyticsStore(analytics);
}
function trackAnalyticsSubscription(plan) {
  const analytics = getAnalyticsStore();
  const key = String(plan || "").toLowerCase();
  const priceMap = {
    starter: 249,
    growth: 599,
    pro: 1200,
    enterprise: 2000
  };
  if (!analytics.subscriptions || typeof analytics.subscriptions !== "object") {
    analytics.subscriptions = { starter: 0, growth: 0, pro: 0, enterprise: 0 };
  }
  analytics.subscriptions[key] = Number(analytics.subscriptions[key] || 0) + 1;
  analytics.revenue = Number(analytics.revenue || 0) + Number(priceMap[key] || 0);
  saveAnalyticsStore(analytics);
}

function orgSettingsDefaults(org_id) {
  return {
    org_id,
    identity: {
      legal_name: "",
      dba_name: "",
      tax_id: "",
      npi: "",
      phone: "",
      fax: "",
      website: "",
      email: "",
      addr_primary: { line1:"", line2:"", city:"", state:"", zip:"" },
      mailing_same_as_primary: true,
      addr_mailing: { line1:"", line2:"", city:"", state:"", zip:"" }
    },
    letter_defaults: {
      appeal_tone: "Professional",
      signature_block: "",
      appeal_opening: "",
      appeal_footer: "",
      negotiation_opening: "",
      negotiation_footer: ""
    },
    allowed_rules: {
      default_method: "percent_billed",
      default_value: 65,
      ucr_multiplier: 1.0,
      tolerance_percent: 1.0,
      tolerance_min_dollars: 5
    },
    workflow_defaults: {
      auto_create_denial_cases: true,
      auto_draft_denials: true,
      auto_draft_underpayments: true,
      default_followup_days: 14,
      require_confirmation_before_submitted: false
    },
    recovery_targets: {
      target_appeal_success_rate: 60,
      target_negotiation_roi: 60,
      target_days_to_pay: 30,
      target_ar90_rate: 15,
      target_operational_discipline: 80
    },
    placeholders: {
      integrations_enabled: false,
      security_mode: "standard"
    },
    created_at: nowISO(),
    updated_at: nowISO()
  };
}

function getOrgSettings(org_id) {
  const all = readJSON(FILES.org_settings, []);
  const existing = all.find(x => x.org_id === org_id) || {};
  const legacyOrg = getOrg(org_id) || {};
  const defaults = orgSettingsDefaults(org_id);
  const merged = {
    ...defaults,
    ...existing,
    identity: {
      ...defaults.identity,
      ...(existing.identity || {}),
      legal_name: String(existing?.identity?.legal_name || legacyOrg.legal_name || legacyOrg.org_name || "").trim(),
      dba_name: String(existing?.identity?.dba_name || legacyOrg.dba_name || "").trim(),
      tax_id: String(existing?.identity?.tax_id || legacyOrg.tax_id || "").trim(),
      npi: String(existing?.identity?.npi || legacyOrg.org_npi || legacyOrg.npi_number || "").trim(),
      phone: String(existing?.identity?.phone || legacyOrg.phone || legacyOrg.main_phone || "").trim(),
      fax: String(existing?.identity?.fax || legacyOrg.fax || "").trim(),
      website: String(existing?.identity?.website || legacyOrg.website || "").trim(),
      email: String(existing?.identity?.email || legacyOrg.org_email || legacyOrg.billing_email || "").trim(),
      mailing_same_as_primary: typeof existing?.identity?.mailing_same_as_primary === "boolean"
        ? existing.identity.mailing_same_as_primary
        : (typeof legacyOrg.addr_mailing_same_as_primary === "boolean" ? legacyOrg.addr_mailing_same_as_primary : true),
      addr_primary: {
        ...defaults.identity.addr_primary,
        ...(existing?.identity?.addr_primary || {}),
        line1: String(existing?.identity?.addr_primary?.line1 || legacyOrg.addr_primary_line1 || legacyOrg.address_line1 || "").trim(),
        line2: String(existing?.identity?.addr_primary?.line2 || legacyOrg.addr_primary_line2 || legacyOrg.address_line2 || "").trim(),
        city: String(existing?.identity?.addr_primary?.city || legacyOrg.addr_primary_city || legacyOrg.city || "").trim(),
        state: String(existing?.identity?.addr_primary?.state || legacyOrg.addr_primary_state || legacyOrg.state || "").trim(),
        zip: String(existing?.identity?.addr_primary?.zip || legacyOrg.addr_primary_zip || legacyOrg.zip || "").trim(),
      },
      addr_mailing: {
        ...defaults.identity.addr_mailing,
        ...(existing?.identity?.addr_mailing || {}),
        line1: String(existing?.identity?.addr_mailing?.line1 || legacyOrg.addr_mailing_line1 || "").trim(),
        line2: String(existing?.identity?.addr_mailing?.line2 || legacyOrg.addr_mailing_line2 || "").trim(),
        city: String(existing?.identity?.addr_mailing?.city || legacyOrg.addr_mailing_city || "").trim(),
        state: String(existing?.identity?.addr_mailing?.state || legacyOrg.addr_mailing_state || "").trim(),
        zip: String(existing?.identity?.addr_mailing?.zip || legacyOrg.addr_mailing_zip || "").trim(),
      }
    },
    letter_defaults: { ...defaults.letter_defaults, ...(existing.letter_defaults || {}) },
    allowed_rules: { ...defaults.allowed_rules, ...(existing.allowed_rules || {}) },
    workflow_defaults: { ...defaults.workflow_defaults, ...(existing.workflow_defaults || {}) },
    recovery_targets: { ...defaults.recovery_targets, ...(existing.recovery_targets || {}) },
    placeholders: { ...defaults.placeholders, ...(existing.placeholders || {}) },
    created_at: existing.created_at || defaults.created_at,
    updated_at: existing.updated_at || defaults.updated_at,
  };
  if (!all.find(x => x.org_id === org_id)) {
    all.push(merged);
    writeJSON(FILES.org_settings, all);
  }
  return merged;
}

function saveOrgSettings(org_id, patch) {
  const all = readJSON(FILES.org_settings, []);
  const idx = all.findIndex(x => x.org_id === org_id);
  const prev = getOrgSettings(org_id);
  const next = {
    ...prev,
    ...patch,
    identity: { ...prev.identity, ...(patch.identity || {}) },
    letter_defaults: { ...prev.letter_defaults, ...(patch.letter_defaults || {}) },
    allowed_rules: { ...prev.allowed_rules, ...(patch.allowed_rules || {}) },
    workflow_defaults: { ...prev.workflow_defaults, ...(patch.workflow_defaults || {}) },
    recovery_targets: { ...prev.recovery_targets, ...(patch.recovery_targets || {}) },
    placeholders: { ...prev.placeholders, ...(patch.placeholders || {}) },
    updated_at: nowISO(),
    created_at: prev.created_at || nowISO(),
    org_id
  };
  if (idx >= 0) all[idx] = next;
  else all.push(next);
  writeJSON(FILES.org_settings, all);
  return next;
}

function getOrgDisplayName(settings, orgRecord) {
  return String(settings?.identity?.legal_name || settings?.identity?.dba_name || orgRecord?.org_name || "Practice").trim() || "Practice";
}

function formatOrgMailingBlock(settings) {
  const identity = settings?.identity || {};
  const mailingSame = typeof identity.mailing_same_as_primary === "boolean" ? identity.mailing_same_as_primary : true;
  const src = mailingSame ? (identity.addr_primary || {}) : (identity.addr_mailing || {});
  return [
    String(src.line1 || "").trim(),
    String(src.line2 || "").trim(),
    [String(src.city || "").trim(), String(src.state || "").trim(), String(src.zip || "").trim()].filter(Boolean).join(", "),
  ].filter(Boolean).join("\n");
}

function getLetterDefaults(settings) {
  return { ...(orgSettingsDefaults("tmp").letter_defaults), ...((settings || {}).letter_defaults || {}) };
}

function getWorkflowDefaults(settings) {
  return { ...(orgSettingsDefaults("tmp").workflow_defaults), ...((settings || {}).workflow_defaults || {}) };
}

function getAllowedRulesFromSettings(settings) {
  return { ...(orgSettingsDefaults("tmp").allowed_rules), ...((settings || {}).allowed_rules || {}) };
}

function getUserByEmail(email) {
  const e = (email || "").toLowerCase();
  return readJSON(FILES.users, []).find(u => (u.email || "").toLowerCase() === e);
}
function getUserById(user_id) {
  return readJSON(FILES.users, []).find(u => u.user_id === user_id);
}
function getPilot(org_id) {
  return readJSON(FILES.pilots, []).find(p => p.org_id === org_id);
}
function ensurePilot(org_id) {
  const pilots = readJSON(FILES.pilots, []);
  let p = pilots.find(x => x.org_id === org_id);
  if (!p) {
    const started = nowISO();
    const ends = addDaysISO(started, PILOT_DAYS);
    p = { pilot_id: uuid(), org_id, status:"active", started_at: started, ends_at: ends, retention_delete_at: null };
    pilots.push(p);
    writeJSON(FILES.pilots, pilots);
  }
  return p;
}
function getSub(org_id) {
  return readJSON(FILES.subscriptions, []).find(s => s.org_id === org_id);
}
function getEffectivePlan(org_id, sess) {
  if (sess && sess.simulating && sess.simulated_plan) {
    return String(sess.simulated_plan).toLowerCase();
  }

  const sub = getSub(org_id);
  return String((sub && sub.plan) || "starter").toLowerCase();
}
function getBillingSummaryForOrg(org_id) {
  const pilot = getPilot(org_id);
  const sub = getSub(org_id);

  let planKey = "starter";
  let status = "inactive";

  if (pilot && pilot.status === "active") {
    planKey = "trial";
    status = "active";
  } else if (sub && sub.plan) {
    planKey = String(sub.plan || "starter").toLowerCase();
    status = String(sub.status || "active");
  }

  const cfg = PLAN_RUNTIME_DEFAULTS[planKey] || PLAN_RUNTIME_DEFAULTS.starter;

  let currentPeriodEnd = "";

  if (pilot && pilot.status === "active") {
    currentPeriodEnd = String(pilot.ends_at || "");
  } else {
    currentPeriodEnd = String(sub?.current_period_end || "");
  }

  return {
    plan: planKey,
    status,
    stripe_customer_id: String(sub?.stripe_customer_id || ""),
    stripe_subscription_id: String(sub?.stripe_subscription_id || ""),
    current_period_end: currentPeriodEnd,
    case_credits_per_month: Number(cfg.case_credits_per_month || 0),
    payment_tracking_credits_per_month: Number(cfg.payment_tracking_credits_per_month || 0),
    ai_chat_limit: Number(cfg.ai_chat_limit || 0),
    copilot_limit: Number(cfg.copilot_limit || 0),
    workspace_limit: Number(cfg.workspace_limit || 0)
  };
}
function currentMonthKey() {
  const d = new Date();
  return `${d.getUTCFullYear()}-${String(d.getUTCMonth()+1).padStart(2,"0")}`;
}
function getUsage(org_id) {
  const usage = readJSON(FILES.usage, []);
  let u = usage.find(x => x.org_id === org_id);
  if (!u) {
    u = {
      org_id,
      pilot_cases_used: 0,
      pilot_payment_rows_used: 0,
      month_key: currentMonthKey(),
      monthly_case_credits_used: 0,
      monthly_case_overage_count: 0,
      monthly_payment_rows_used: 0,
      monthly_payment_credits_used: 0,
      monthly_ai_generations_used: 0,
      monthly_agent_workspace_edits: 0,
      ai_workspace_used: 0,
      ai_job_timestamps: [],
      ai_chat_used: 0,
      copilot_used: 0,
      copilot_questions_used: 0,
      ai_copilot_queries_used: 0,
      ai_copilot_query_limit: 0,
      claims_processed: 0
    };
    usage.push(u);
    writeJSON(FILES.usage, usage);
  }
  if (u.month_key !== currentMonthKey()) {
    u.month_key = currentMonthKey();
    u.monthly_case_credits_used = 0;
    u.monthly_case_overage_count = 0;
    u.monthly_payment_rows_used = 0;
    u.monthly_payment_credits_used = 0;
    u.monthly_ai_generations_used = 0;
    u.monthly_agent_workspace_edits = 0;
    u.ai_chat_used = 0;
    u.copilot_used = 0;
    u.copilot_questions_used = 0;
    u.ai_copilot_queries_used = 0;
    u.ai_copilot_query_limit = 0;
    u.claims_processed = 0;
    writeJSON(FILES.usage, usage);
  }
  if (typeof u.monthly_ai_generations_used !== "number") u.monthly_ai_generations_used = 0;
  if (typeof u.monthly_agent_workspace_edits !== "number") u.monthly_agent_workspace_edits = 0;
  if (typeof u.ai_workspace_used !== "number") u.ai_workspace_used = 0;

  // 🔥 CANONICAL COPILOT USAGE (single source of truth)
  if (typeof u.copilot_used !== "number") {
    u.copilot_used = Number(
      u.copilot_used ??
      u.ai_copilot_queries_used ??
      u.copilot_questions_used ??
      0
    );
  }

  // force ALL legacy fields to match
  u.ai_copilot_queries_used = u.copilot_used;
  u.copilot_questions_used = u.copilot_used;
  writeJSON(FILES.usage, usage);
  if (typeof u.ai_copilot_query_limit !== "number") u.ai_copilot_query_limit = Number(getCopilotLimit(org_id) || 0);
  if (typeof u.claims_processed !== "number") u.claims_processed = Number(u.monthly_case_credits_used || u.pilot_cases_used || 0);
  return u;
}
function saveUsage(u) {
  const usage = readJSON(FILES.usage, []);
  const idx = usage.findIndex(x => x.org_id === u.org_id);
  if (idx >= 0) usage[idx] = u; else usage.push(u);
  writeJSON(FILES.usage, usage);
}
function auditLog(entry) {
  const audit = readJSON(FILES.audit, []);
  audit.push({ ...entry, at: nowISO() });
  writeJSON(FILES.audit, audit);
}


