function getCopilotWorkspaces(org_id){
  return readJSON(FILES.copilot_workspaces, [])
    .filter(w => w.org_id === org_id)
    .sort((a,b)=> new Date(b.updated_at||0)-new Date(a.updated_at||0));
}

function getCopilotWorkspace(org_id, workspace_id){
  return readJSON(FILES.copilot_workspaces, [])
    .find(w => w.org_id === org_id && w.workspace_id === workspace_id) || null;
}

function saveCopilotWorkspace(workspace){
  const all = readJSON(FILES.copilot_workspaces, []);
  const keep = all.filter(w => w.workspace_id !== workspace.workspace_id);
  writeJSON(FILES.copilot_workspaces, keep.concat([workspace]));
}

function getCopilotUsageSnapshot(org_id) {
  const usage = getUsage(org_id);
  const limits = getLimitProfile(org_id);
  const used = Number(usage.copilot_used || 0);

  let limit = limits.mode === "pilot"
    ? 10
    : Number(limits.copilot_limit || usage.ai_copilot_query_limit || Infinity);

  if (!Number.isFinite(limit) || limit >= 999999) {
    limit = Infinity;
  }

  const isUnlimited = !Number.isFinite(limit);
  const remaining = isUnlimited ? Infinity : Math.max(0, limit - used);
  const hasAccess = isUnlimited || used < limit;
  const limitReached = !hasAccess;
  return { usage, limits, used, limit, remaining, isUnlimited, hasAccess, limitReached };
}

function getCopilotLimitMessage(org_id) {
  const snap = getCopilotUsageSnapshot(org_id);
  if (!snap.limitReached) return null;

  const sub = getSub(org_id);
  const pilot = getPilot(org_id) || ensurePilot(org_id);

  // Free trial / pilot case
  if (!sub || !sub.plan || (pilot && pilot.status === "active")) {
    return {
      type: "trial",
      message: "AI Copilot trial limit reached. Upgrade for unlimited access."
    };
  }

  // Paid plan case (monthly reset)
  const now = new Date();
  const nextMonth = new Date(Date.UTC(
    now.getUTCFullYear(),
    now.getUTCMonth() + 1,
    1
  ));

  return {
    type: "subscription",
    message: `Limit reached. Your AI Copilot usage resets on ${nextMonth.toLocaleDateString()}. Upgrade for higher limits.`
  };
}

function consumeCopilotQuery(org_id) {
  const { usage, used, limit, hasAccess } = getCopilotUsageSnapshot(org_id);

  if (!hasAccess) {
    const limitInfo = getCopilotLimitMessage(org_id);
    return {
      ok: false,
      used,
      limit,
      message: limitInfo?.message || "AI Copilot limit reached."
    };
  }

  const nextUsed = used + 1;

  usage.copilot_used = nextUsed;
  usage.ai_copilot_queries_used = nextUsed;
  usage.copilot_questions_used = nextUsed;

  saveUsage(usage);

  return { ok: true, used: nextUsed, limit };
}

function createCopilotWorkspaceFromPrompt(org_id, prompt) {
  const workspace_id = uuid();
  const result = buildCopilotResponse({
    org_id,
    rangePreset: "last30",
    responseFormat: "executive",
    question: prompt,
  });

  const briefs = readJSON(FILES.copilot_briefs, []);
  const brief_id = "BRF-" + Date.now();
  briefs.push({ brief_id, org_id, created: nowISO(), result });
  writeJSON(FILES.copilot_briefs, briefs);

  const workspace = {
    workspace_id,
    org_id,
    title: prompt.slice(0, 60),
    messages: [
      { role: "user", content: prompt, created_at: nowISO() },
      { role: "assistant", content: buildExecutiveTitle(result), created_at: nowISO() }
    ],
    latest_brief: { brief_id, result },
    created_at: nowISO(),
    updated_at: nowISO(),
  };
  saveCopilotWorkspace(workspace);
  return workspace;
}

// ===========================
// Context-Aware Brief Title
// ===========================
function buildExecutiveTitle(result) {
  if (!result) return "Financial Performance Snapshot";
  if (result.briefTitle) return String(result.briefTitle);

  if (result.payerScope) {
    return `${result.payerScope} Performance Snapshot (Last 30 Days)`;
  }

  return "Financial Performance Snapshot";
}

function ensureSubscriptionForOrg(org_id) {
  const subs = readJSON(FILES.subscriptions, []);
  let s = subs.find(x => x.org_id === org_id);
  if (!s) {
    s = {
      sub_id: uuid(),
      org_id,
      status: "inactive",
      plan: "",
      customer_email: "",
      case_credits_per_month: MONTHLY_DEFAULTS.case_credits_per_month,
      payment_tracking_credits_per_month: MONTHLY_DEFAULTS.payment_tracking_credits_per_month,
      copilot_limit: PLAN_RUNTIME_DEFAULTS.starter.copilot_limit,
      workspace_limit: PLAN_RUNTIME_DEFAULTS.starter.workspace_limit,
      updated_at: nowISO()
    };
    subs.push(s);
    writeJSON(FILES.subscriptions, subs);
  }
  return s;
}

function upsertSubscriptionFromStripe(data) {
  const subs = readJSON(FILES.subscriptions, []);
  const users = readJSON(FILES.users, []);

  const customerId = String(data.customer || "");
  const subscriptionId = String(data.id || data.subscription || "");
  const status = String(data.status || "");
  const currentPeriodEnd =
    data.current_period_end
      ? new Date(Number(data.current_period_end) * 1000).toISOString()
      : "";

  const plan =
    data.items && data.items.data && data.items.data[0] && data.items.data[0].price
      ? String(data.items.data[0].price.nickname || data.metadata?.plan || "").toLowerCase()
      : String(data.metadata?.plan || "").toLowerCase();

  let sub = subs.find(s =>
    String(s.stripe_subscription_id || "") === subscriptionId ||
    String(s.stripe_customer_id || "") === customerId
  );

  let orgId = sub?.org_id || "";

  if (!orgId && customerId) {
    const user = users.find(u => String(u.stripe_customer_id || "") === customerId);
    if (user) orgId = user.org_id;
  }

  if (!sub) {
    sub = {
      subscription_id: uuid(),
      org_id: orgId || "",
      status: status || "active",
      plan: plan || "starter",
      stripe_customer_id: customerId,
      stripe_subscription_id: subscriptionId,
      current_period_end: currentPeriodEnd,
      created_at: nowISO(),
      updated_at: nowISO()
    };
    subs.push(sub);
  } else {
    sub.org_id = orgId || sub.org_id || "";
    sub.status = status || sub.status || "";
    sub.plan = plan || sub.plan || "starter";
    sub.stripe_customer_id = customerId || sub.stripe_customer_id || "";
    sub.stripe_subscription_id = subscriptionId || sub.stripe_subscription_id || "";
    sub.current_period_end = currentPeriodEnd || sub.current_period_end || "";
    sub.updated_at = nowISO();
  }

  writeJSON(FILES.subscriptions, subs);

  if (orgId) {
    const userIdxs = users
      .map((u, i) => ({ u, i }))
      .filter(x => String(x.u.org_id || "") === String(orgId));

    userIdxs.forEach(({ i }) => {
      users[i].subscription_status = sub.status;
      users[i].plan = sub.plan;
      users[i].stripe_customer_id = sub.stripe_customer_id;
      users[i].stripe_subscription_id = sub.stripe_subscription_id;
    });

    writeJSON(FILES.users, users);
  }
}

function markSubscriptionCanceledByStripe(customerId, subscriptionId) {
  const subs = readJSON(FILES.subscriptions, []);
  const users = readJSON(FILES.users, []);

  const sub = subs.find(s =>
    String(s.stripe_subscription_id || "") === String(subscriptionId || "") ||
    String(s.stripe_customer_id || "") === String(customerId || "")
  );

  if (sub) {
    sub.status = "canceled";
    sub.updated_at = nowISO();
    writeJSON(FILES.subscriptions, subs);

    users.forEach(u => {
      if (String(u.org_id || "") === String(sub.org_id || "")) {
        u.subscription_status = "canceled";
      }
    });
    writeJSON(FILES.users, users);
  }
}

function markSubscriptionPastDueByStripe(customerId, subscriptionId) {
  const subs = readJSON(FILES.subscriptions, []);
  const users = readJSON(FILES.users, []);

  const sub = subs.find(s =>
    String(s.stripe_subscription_id || "") === String(subscriptionId || "") ||
    String(s.stripe_customer_id || "") === String(customerId || "")
  );

  if (sub) {
    sub.status = "past_due";
    sub.updated_at = nowISO();
    writeJSON(FILES.subscriptions, subs);

    users.forEach(u => {
      if (String(u.org_id || "") === String(sub.org_id || "")) {
        u.subscription_status = "past_due";
      }
    });
    writeJSON(FILES.users, users);
  }
}

function applyPlanToSubscription(sub, planName) {
  const key = (planName || "").toLowerCase();
  const cfg = PLAN_RUNTIME_DEFAULTS[key] || PLAN_RUNTIME_DEFAULTS.starter;
  sub.plan = key;
  sub.case_credits_per_month = cfg.case_credits_per_month;
  sub.payment_tracking_credits_per_month = cfg.payment_tracking_credits_per_month;
  sub.ai_chat_limit = cfg.ai_chat_limit;
  sub.copilot_limit = cfg.copilot_limit;
  sub.workspace_limit = cfg.workspace_limit;
  sub.status = "active";
  sub.updated_at = nowISO();

  const users = readJSON(FILES.users, []);
  let changed = false;
  users.forEach(user => {
    if (user.org_id === sub.org_id) {
      user.plan = key;
      user.subscription_status = "active";
      if (typeof user.stripe_customer_id !== "string") user.stripe_customer_id = "";
      if (typeof user.stripe_subscription_id !== "string") user.stripe_subscription_id = "";
      changed = true;
    }
  });
  if (changed) writeJSON(FILES.users, users);

  trackAnalyticsSubscription(key);
}

// ===== Account status =====
function getOrgStatus(org_id) {
  const org = getOrg(org_id);
  return org?.account_status || "active";
}
function setOrgStatus(org_id, status, reason="") {
  const orgs = readJSON(FILES.orgs, []);
  const idx = orgs.findIndex(o => o.org_id === org_id);
  if (idx < 0) return;
  orgs[idx].account_status = status; // active|suspended|terminated
  orgs[idx].status_reason = reason || null;
  orgs[idx].status_updated_at = nowISO();
  writeJSON(FILES.orgs, orgs);
}

// ===== Pilot/sub access =====
function markPilotComplete(org_id) {
  const pilots = readJSON(FILES.pilots, []);
  const idx = pilots.findIndex(p => p.org_id === org_id);
  if (idx < 0) return;
  pilots[idx].status = "complete";
  pilots[idx].retention_delete_at = addDaysISO(pilots[idx].ends_at, RETENTION_DAYS_AFTER_PILOT);
  writeJSON(FILES.pilots, pilots);
}

function isAccessEnabled(org_id) {
  const status = getOrgStatus(org_id);
  if (status === "terminated" || status === "suspended") return false;

  const sub = getSub(org_id);
  if (sub && sub.status === "active") return true;

  // Pilot = 10 total questions for the 14-day trial
  const pilot = getPilot(org_id) || ensurePilot(org_id);
  if (new Date(pilot.ends_at).getTime() < Date.now() && pilot.status !== "complete") {
    markPilotComplete(org_id);
  }
  const p2 = getPilot(org_id);
  return p2 && p2.status === "active";
}

function cleanupIfExpired(org_id) {
  const sub = getSub(org_id);
  if (sub && sub.status === "active") return;

  const pilot = getPilot(org_id);
  if (!pilot) return;

  if (pilot.status !== "complete") {
    if (new Date(pilot.ends_at).getTime() < Date.now()) markPilotComplete(org_id);
    return;
  }
  if (!pilot.retention_delete_at) return;

  const delAt = new Date(pilot.retention_delete_at).getTime();
  if (Date.now() < delAt) return;

  // Delete org-scoped files and data
  const cases = readJSON(FILES.cases, []).filter(c => c.org_id !== org_id);
  const payments = readJSON(FILES.payments, []).filter(p => p.org_id !== org_id);
  const expectations = readJSON(FILES.expectations, []).filter(e => e.org_id !== org_id);
  const flags = readJSON(FILES.flags, []).filter(f => f.org_id !== org_id);

  writeJSON(FILES.cases, cases);
  writeJSON(FILES.payments, payments);
  writeJSON(FILES.expectations, expectations);
  writeJSON(FILES.flags, flags);

  const orgUploads = path.join(UPLOADS_DIR, org_id);
  if (fs.existsSync(orgUploads)) fs.rmSync(orgUploads, { recursive:true, force:true });
}

// ===== Limits =====
function getLimitProfile(org_id) {
  const sess = CURRENT_SIMULATION
    ? { simulating:true, simulated_plan: CURRENT_SIMULATION.plan }
    : null;

  const simulatedPlan = getEffectivePlan(org_id, sess);

  // 🔥 SIMULATION MODE
  if (sess && sess.simulating) {
    const cfg = PLAN_RUNTIME_DEFAULTS[simulatedPlan] || PLAN_RUNTIME_DEFAULTS.starter;
    return {
      mode: "monthly",
      copilot_limit: cfg.copilot_limit,
      workspace_limit: cfg.workspace_limit,
      case_credits_per_month: cfg.case_credits_per_month,
      payment_tracking_credits_per_month: cfg.payment_tracking_credits_per_month,
      max_files_per_case: MONTHLY_DEFAULTS.max_files_per_case,
      max_file_size_mb: MONTHLY_DEFAULTS.max_file_size_mb,
      max_ai_jobs_per_hour: MONTHLY_DEFAULTS.max_ai_jobs_per_hour,
      max_concurrent_analyzing: MONTHLY_DEFAULTS.max_concurrent_analyzing,
      overage_price_per_case: MONTHLY_DEFAULTS.overage_price_per_case,
      payment_records_per_credit: MONTHLY_DEFAULTS.payment_records_per_credit,
    };
  }

  // ✅ REAL LOGIC (unchanged)
  const sub = getSub(org_id);
  if (sub && sub.status === "active") {
    return {
      mode: "monthly",
      copilot_limit: sub.copilot_limit || 150,
      workspace_limit: sub.workspace_limit || 50,
      case_credits_per_month: sub.case_credits_per_month || MONTHLY_DEFAULTS.case_credits_per_month,
      payment_tracking_credits_per_month: sub.payment_tracking_credits_per_month || MONTHLY_DEFAULTS.payment_tracking_credits_per_month,
      max_files_per_case: MONTHLY_DEFAULTS.max_files_per_case,
      max_file_size_mb: MONTHLY_DEFAULTS.max_file_size_mb,
      max_ai_jobs_per_hour: MONTHLY_DEFAULTS.max_ai_jobs_per_hour,
      max_concurrent_analyzing: MONTHLY_DEFAULTS.max_concurrent_analyzing,
      overage_price_per_case: MONTHLY_DEFAULTS.overage_price_per_case,
      payment_records_per_credit: MONTHLY_DEFAULTS.payment_records_per_credit,
    };
  }

  return {
    mode: "pilot",
    copilot_limit: 10,
    workspace_limit: 5,
    ...PILOT_LIMITS
  };
}

function countOrgCases(org_id) {
  return readJSON(FILES.cases, []).filter(c => c.org_id === org_id).length;
}
function countOrgAnalyzing(org_id) {
  return readJSON(FILES.cases, []).filter(c => c.org_id === org_id && c.status === "ANALYZING").length;
}

function canStartAI(org_id) {
  const limits = getLimitProfile(org_id);
  const usage = getUsage(org_id);

  const analyzing = countOrgAnalyzing(org_id);
  const cap = limits.max_concurrent_analyzing;
  if (analyzing >= cap) return { ok:false, reason:`Concurrent processing limit reached (${cap}). Try again shortly.` };

  const perHour = limits.max_ai_jobs_per_hour;
  const cutoff = Date.now() - 60*60*1000;
  usage.ai_job_timestamps = (usage.ai_job_timestamps || []).filter(ts => ts > cutoff);

  if (usage.ai_job_timestamps.length >= perHour) {
    saveUsage(usage);
    return { ok:false, reason:`AI job rate limit reached (${perHour}/hour). Try again shortly.` };
  }
  return { ok:true };
}
function recordAIJob(org_id) {
  const usage = getUsage(org_id);
  const cutoff = Date.now() - 60*60*1000;
  usage.ai_job_timestamps = (usage.ai_job_timestamps || []).filter(ts => ts > cutoff);
  usage.ai_job_timestamps.push(Date.now());
  saveUsage(usage);
}

function pilotCanCreateCase(org_id) {
  const limits = getLimitProfile(org_id);
  if (limits.mode !== "pilot") return { ok:true };
  const total = countOrgCases(org_id);
  if (total >= limits.max_cases_total) return { ok:false, reason:`Pilot case limit reached (${limits.max_cases_total}). Continue monthly access to review more.` };
  return { ok:true };
}
function pilotConsumeCase(org_id) {
  const usage = getUsage(org_id);
  usage.pilot_cases_used += 1;
  saveUsage(usage);
}
function monthlyConsumeCaseCredit(org_id) {
  const limits = getLimitProfile(org_id);
  if (limits.mode !== "monthly") return { ok:true, overage:false };
  const usage = getUsage(org_id);
  usage.monthly_case_credits_used += 1;
  let overage = false;
  if (usage.monthly_case_credits_used > limits.case_credits_per_month) {
    overage = true;
    usage.monthly_case_overage_count += 1;
  }
  saveUsage(usage);
  return { ok:true, overage };
}

function paymentRowsAllowance(org_id) {
  const limits = getLimitProfile(org_id);
  const usage = getUsage(org_id);

  if (limits.mode === "pilot") {
    const remaining = Math.max(0, PILOT_LIMITS.payment_records_included - (usage.pilot_payment_rows_used || 0));
    return { remaining, mode:"pilot" };
  }
  const allowedRows = (limits.payment_tracking_credits_per_month || 0) * PAYMENT_RECORDS_PER_CREDIT;
  const used = usage.monthly_payment_rows_used || 0;
  return { remaining: Math.max(0, allowedRows - used), mode:"monthly" };
}

function consumePaymentRows(org_id, rowCount) {
  const limits = getLimitProfile(org_id);
  const usage = getUsage(org_id);

  if (limits.mode === "pilot") {
    usage.pilot_payment_rows_used = (usage.pilot_payment_rows_used || 0) + rowCount;
    saveUsage(usage);
    return;
  }
  usage.monthly_payment_rows_used = (usage.monthly_payment_rows_used || 0) + rowCount;
  usage.monthly_payment_credits_used = (usage.monthly_payment_credits_used || 0) + Math.ceil(rowCount / PAYMENT_RECORDS_PER_CREDIT);
  saveUsage(usage);
}


function money(n){
  const x = Number(n || 0);
  return x.toLocaleString("en-US", { style: "currency", currency: "USD" });
}

function num(v){
  const n = Number(String(v||"").replace(/[^0-9.\-]/g,""));
  return isFinite(n) ? n : 0;
}


// ===== Money formatting helpers (UI) =====
function formatMoney(val) {
  return "$" + Number(val || 0).toLocaleString(undefined, {minimumFractionDigits:2, maximumFractionDigits:2});
}
// Returns <td>Billed</td><td Paid> with highlight when paid < billed
function billedPaidCell(billed, paid) {
  const b = Number(billed || 0);
  const p = Number(paid || 0);
  const style = (p + 0.0001 < b) ? 'style="color:#d97706;font-weight:900;"' : '';
  return `<td>${formatMoney(b)}</td><td ${style}>${formatMoney(p)}</td>`;
}

function computeExpectedInsurance(allowedAmount, patientResp){
  const allowed = num(allowedAmount);
  const pr = Math.max(0, num(patientResp));
  return Math.max(0, allowed - pr);
}

function computeUnderpaidAmount(expectedInsurance, actualInsurancePaid){
  const exp = num(expectedInsurance);
  const act = num(actualInsurancePaid);
  return Math.max(0, exp - act);
}

// ===== Multipart Parser =====
async function parseMultipart(req, boundary) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    req.on("data", c => chunks.push(c));
    req.on("end", () => {
      const buffer = Buffer.concat(chunks);
      const boundaryBuf = Buffer.from(`--${boundary}`);
      const parts = [];

      let start = buffer.indexOf(boundaryBuf);
      while (start !== -1) {
        const end = buffer.indexOf(boundaryBuf, start + boundaryBuf.length);
        if (end === -1) break;
        const part = buffer.slice(start + boundaryBuf.length, end);
        if (part.length < 4) break;
        parts.push(part);
        start = end;
      }

      const files = [];
      const fields = {};

      for (const raw of parts) {
        const part = raw.slice(2);
        const headerEnd = part.indexOf(Buffer.from("\r\n\r\n"));
        if (headerEnd === -1) continue;

        const headerText = part.slice(0, headerEnd).toString("utf8");
        const content = part.slice(headerEnd + 4, part.length - 2);

        const nameMatch = /name="([^"]+)"/.exec(headerText);
        if (!nameMatch) continue;
        const fieldName = nameMatch[1];

        const fileMatch = /filename="([^"]*)"/.exec(headerText);
        if (fileMatch && fileMatch[1]) {
          const filename = fileMatch[1];
          const mimeMatch = /Content-Type:\s*([^\r\n]+)/.exec(headerText);
          const mime = mimeMatch ? mimeMatch[1].trim() : "application/octet-stream";
          files.push({ fieldName, filename, mime, buffer: content });
        } else {
          fields[fieldName] = content.toString("utf8");
        }
      }

      resolve({ files, fields });
    });
    req.on("error", reject);
  });
}

// ===== CSV parser =====
function parseCSV(text) {
  const lines = text.split(/\r?\n/).filter(l => l.trim().length);
  if (!lines.length) return { headers: [], rows: [] };

  function splitLine(line) {
    const out = [];
    let cur = "";
    let inQ = false;
    for (let i=0;i<line.length;i++){
      const ch = line[i];
      if (ch === '"') {
        if (inQ && line[i+1] === '"') { cur += '"'; i++; }
        else inQ = !inQ;
      } else if (ch === "," && !inQ) {
        out.push(cur); cur="";
      } else {
        cur += ch;
      }
    }
    out.push(cur);
    return out.map(s => s.trim());
  }

  const headers = splitLine(lines[0]).map(h => h.replace(/^"|"$/g,"").trim());
  const rows = [];
  for (let i=1;i<lines.length;i++){
    const cols = splitLine(lines[i]).map(c => c.replace(/^"|"$/g,""));
    const obj = {};
    headers.forEach((h, idx) => obj[h] = cols[idx] || "");
    rows.push(obj);
  }
  return { headers, rows };
}

function pickField(row, candidates) {
  const keys = Object.keys(row || {});
  for (const c of candidates) {
    const k = keys.find(x => x.toLowerCase().includes(c));
    if (k) return row[k];
  }
  return "";
}

function detectReimbursementUploadType(file, parsedCsv) {
  const headers = (parsedCsv.headers || []).map(h => String(h || "").toLowerCase().trim());
  const hasAny = (candidates) => candidates.some(c => headers.some(h => h.includes(c)));

  const contractSignals = [
    "payer_name", "network_status", "diagnosis_code", "reimbursement_model", "allowed_amount", "effective_date"
  ];
  const feeSignals = ["schedule_type", "locality", "year", "rate", "fee", "amount"];

  const contractScore = contractSignals.filter(s => hasAny([s])).length
    + (hasAny(["payer", "insurance", "carrier"]) ? 1 : 0)
    + (hasAny(["procedure_code", "cpt"]) ? 1 : 0);
  const feeScore = feeSignals.filter(s => hasAny([s])).length
    + (hasAny(["procedure_code", "cpt", "hcpcs"]) ? 1 : 0)
    + (hasAny(["allowed", "amount", "rate", "fee"]) ? 1 : 0);

  if (contractScore > feeScore) return "contract";
  if (feeScore > contractScore) return "fee_schedule";

  const filename = String(file.filename || "").toLowerCase();
  if (filename.includes("contract")) return "contract";
  if (filename.includes("fee") || filename.includes("schedule")) return "fee_schedule";
  return "unknown";
}

function saveReimbursementUploadLog(entry){
  const logs = readJSON(FILES.reimbursement_uploads, []);
  logs.push(entry);
  writeJSON(FILES.reimbursement_uploads, logs);
}
function getReimbursementUploadLogs(org_id){
  return readJSON(FILES.reimbursement_uploads, [])
    .filter(x => x.org_id === org_id)
    .sort((a,b)=> new Date(b.created_at||0) - new Date(a.created_at||0));
}
function savePendingReimbursement(pending){
  const all = readJSON(FILES.pending_reimbursement_uploads, []);
  all.push(pending);
  writeJSON(FILES.pending_reimbursement_uploads, all);
}
function getPendingReimbursement(org_id, token){
  return readJSON(FILES.pending_reimbursement_uploads, [])
    .find(x => x.org_id === org_id && x.token === token) || null;
}
function deletePendingReimbursement(org_id, token){
  const all = readJSON(FILES.pending_reimbursement_uploads, []);
  const keep = all.filter(x => !(x.org_id === org_id && x.token === token));
  writeJSON(FILES.pending_reimbursement_uploads, keep);
}

// ===============================
// AI Contract Validation Engine (Rule-Based MVP)
// ===============================
function validateContractBatch(org_id, newContracts) {
  const existing = getPayerContracts(org_id);
  const issues = [];
  const warnings = [];
  const seenKeys = new Set();

  for (const c of newContracts) {

    const key = `${c.payer_name}|${c.procedure_code}|${c.network_status}`;
    if (seenKeys.has(key)) {
      issues.push(`Duplicate in upload: ${key}`);
    }
    seenKeys.add(key);

    if (!c.payer_name || !c.procedure_code) {
      issues.push(`Missing required fields for CPT ${c.procedure_code || "UNKNOWN"}`);
    }

    if (!c.reimbursement_model) {
      issues.push(`Missing reimbursement model for ${c.payer_name} ${c.procedure_code}`);
    }

    if (c.reimbursement_model === "percent_of_charge") {
      if (c.expected_value <= 0 || c.expected_value > 200) {
        warnings.push(`Unusual percentage value (${c.expected_value}%) for ${c.payer_name} ${c.procedure_code}`);
      }
    }

    if (c.reimbursement_model === "fixed_amount") {
      if (c.expected_value <= 0) {
        issues.push(`Invalid fixed amount for ${c.payer_name} ${c.procedure_code}`);
      }
      if (c.expected_value > 10000) {
        warnings.push(`Unusually high fixed reimbursement (${c.expected_value}) for ${c.payer_name} ${c.procedure_code}`);
      }
    }

    const conflict = existing.find(e =>
      e.payer_name === c.payer_name &&
      e.procedure_code === c.procedure_code &&
      e.network_status === c.network_status &&
      e.reimbursement_model !== c.reimbursement_model
    );

    if (conflict) {
      warnings.push(`Model conflict detected for ${c.payer_name} ${c.procedure_code}`);
    }
  }

  return {
    issues,
    warnings,
    valid: issues.length === 0
  };
}

function runExtractionFromDocumentText() {
  return { claims: [] };
}

function findClaimByHeuristics(org_id, billedAll, extracted){
  const claimNum = normalizeClaimDigits(extracted.claim_number);
  if (claimNum) {
    const byClaim = billedAll.find(b => b.org_id === org_id && normalizeClaimDigits(b.claim_number) === claimNum);
    if (byClaim) return byClaim;
  }
  const payer = String(extracted.payer || "").trim().toLowerCase();
  const dos = String(extracted.dos || "").trim();
  const billedAmt = num(extracted.billed_amount);
  if (payer && dos) {
    const byPayerDos = billedAll.find(b => b.org_id === org_id && String(b.payer || "").trim().toLowerCase() === payer && String(b.dos || "").trim() === dos);
    if (byPayerDos) return byPayerDos;
  }
  if (payer && billedAmt > 0) {
    const byPayerAmount = billedAll.find(b => b.org_id === org_id && String(b.payer || "").trim().toLowerCase() === payer && Math.abs(num(b.amount_billed) - billedAmt) < 0.01);
    if (byPayerAmount) return byPayerAmount;
  }
  return null;
}

