function workspaceChannelForClaim(claim, derived){
  const d = derived && derived.lifecycleStage ? derived : evaluateClaimDerived(claim, buildClaimContext(claim?.org_id));
  const stage = String(d?.lifecycleStage || "");
  if (stage === "Denied" || d?.hasDenialContext) return "appeal";
  if (stage === "Underpaid") return "negotiation";
  if (stage === "In Appeal/Negotiation") return Number(d?.underpaidAmount || 0) > 0 ? "negotiation" : "appeal";
  return Number(d?.underpaidAmount || 0) > 0 ? "negotiation" : "appeal";
}

function packetNarrativeKey(channel){
  return channel === "negotiation" ? "variance_explanation" : "argument";
}

function packetSectionDescriptions(channel){
  if (channel === "negotiation") {
    return {
      header: "Letter header and identifiers.",
      claim_summary: "Claim context, payer, DOS, and status.",
      financial_summary: "Billed vs expected vs paid snapshot.",
      variance_explanation: "Core negotiation narrative for variance.",
      requested_amount: "Target reimbursement amount requested.",
      requested_action: "Specific adjustment steps requested.",
      attachments_index: "Attachment index and missing-item hints.",
      signature: "Organization signature/contact block."
    };
  }
  return {
    header: "Letter header and identifiers.",
    claim_summary: "Claim context, denial reason, and payer details.",
    financial_summary: "Billed vs expected vs paid snapshot.",
    argument: "Core appeal argument and medical/contract basis.",
    requested_action: "Specific reversal/reprocessing actions requested.",
    attachments_index: "Attachment index and missing-item hints.",
    signature: "Organization signature/contact block."
  };
}

function detectEobEraForClaim(org_id, claim, ws){
  const hasWorkspaceEob = (ws?.attachments || []).some(a => ["eob", "era"].includes(String(a.kind || "").toLowerCase()));
  const hasPacketEob = packetHasKey(ws, "eob_era");
  const hasClaimDenialDoc = !!(claim?.denial_doc_attached || claim?.denial_document || claim?.denial_file);
  const ingests = readJSON(FILES.document_ingests, []).filter(x => x.org_id === org_id);
  const hasIngestEob = ingests.some(x => {
    const blob = `${x.category || ""} ${x.original_filename || ""} ${x.notes || ""}`.toLowerCase();
    return blob.includes("eob") || blob.includes("era") || blob.includes("denial");
  });
  return hasWorkspaceEob || hasPacketEob || hasClaimDenialDoc || hasIngestEob;
}



function normalizeDenialReasonKey(v){
  return String(v || "").trim().toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "") || "unknown";
}

function extractPacketFeatures({ argumentText, requestedActionText, attachmentsState, hasContract, hasDenialLetter, hasEob, hasClaimForm, hasMedicalRecords, hasPolicyCitation, hasContractCitation }){
  const aText = String(argumentText || "").trim();
  const rText = String(requestedActionText || "").trim();
  const at = attachmentsState || {};
  const denial = typeof hasDenialLetter === "boolean" ? hasDenialLetter : !!at.hasDenialLetter;
  const eob = typeof hasEob === "boolean" ? hasEob : !!at.hasEob;
  const claimForm = typeof hasClaimForm === "boolean" ? hasClaimForm : !!at.hasClaimForm;
  const med = typeof hasMedicalRecords === "boolean" ? hasMedicalRecords : !!at.hasMedicalRecords;
  const policy = typeof hasPolicyCitation === "boolean" ? hasPolicyCitation : /policy|benefit|coverage|guideline|lcd|ncd|cpt|icd/i.test(aText + " " + rText);
  const contractCite = typeof hasContractCitation === "boolean" ? hasContractCitation : /contract|fee schedule|allowed amount|reimbursement|participating|agreement/i.test(aText + " " + rText);
  const argumentLength = aText.length;
  const requestedActionLength = rText.length;
  const hasClearAsk = requestedActionLength > 40;
  let completenessScore = 0;
  completenessScore += denial ? 20 : 0;
  completenessScore += eob ? 20 : 0;
  completenessScore += claimForm ? 15 : 0;
  completenessScore += med ? 10 : 0;
  completenessScore += policy ? 10 : 0;
  completenessScore += contractCite ? 10 : 0;
  completenessScore += argumentLength >= 200 ? 10 : 0;
  completenessScore += hasClearAsk ? 5 : 0;
  completenessScore = Math.max(0, Math.min(100, completenessScore));
  return {
    hasDenialLetter: denial,
    hasEob: eob,
    hasClaimForm: claimForm,
    hasMedicalRecords: med,
    hasPolicyCitation: policy,
    hasContractCitation: contractCite,
    argumentLength,
    requestedActionLength,
    hasClearAsk,
    completenessScore,
    hasContract: !!hasContract,
  };
}

function loadWorkspaceOutcomes(org_id){
  return readJSON(FILES.workspace_outcomes, []).filter(r => r && r.org_id === org_id);
}

function saveWorkspaceOutcome(record){
  const all = readJSON(FILES.workspace_outcomes, []);
  all.push({ ...record, created_at: record.created_at || nowISO() });
  writeJSON(FILES.workspace_outcomes, all);
}

function computePayerBehaviorIntelligence(org_id, payer){
  const rows = readJSON(FILES.workspace_outcomes, []).filter(r =>
    r &&
    r.org_id === org_id &&
    String(r.payer || "").trim().toLowerCase() === String(payer || "").trim().toLowerCase()
  );

  if (!rows.length) return null;

  const successSet = new Set(["approved", "partial", "paid_in_full"]);
  const appealRows = rows.filter(r => String(r.stage_type || "") === "appeal");
  const negotiationRows = rows.filter(r => String(r.stage_type || "") === "negotiation");
  const appealSuccesses = appealRows.filter(r => successSet.has(String(r.outcome_status || "")));
  const negotiationSuccesses = negotiationRows.filter(r => successSet.has(String(r.outcome_status || "")));

  const appealSuccessRate = appealRows.length ? (appealSuccesses.length / appealRows.length) : 0;
  const negotiationSuccessRate = negotiationRows.length ? (negotiationSuccesses.length / negotiationRows.length) : 0;

  const allSuccesses = rows.filter(r => successSet.has(String(r.outcome_status || "")));
  const avgRecoveredPct = allSuccesses.length
    ? allSuccesses.reduce((sum, r) => {
        const req = num(r.requested_amount);
        const rec = num(r.recovered_amount);
        return sum + (req > 0 ? (rec / req) : 0);
      }, 0) / allSuccesses.length
    : 0;

  const dayVals = rows.map(r => Number(r.days_to_payment)).filter(v => Number.isFinite(v) && v >= 0);
  const avgDays = dayVals.length ? (dayVals.reduce((sum, v) => sum + v, 0) / dayVals.length) : null;

  const strategyCounts = {};
  const strategySuccess = {};
  const strategyDays = {};
  rows.forEach(r => {
    const k = String(r.strategy_profile_used || "Auto") || "Auto";
    strategyCounts[k] = (strategyCounts[k] || 0) + 1;
    if (!strategySuccess[k]) strategySuccess[k] = { n: 0, s: 0 };
    strategySuccess[k].n += 1;
    if (successSet.has(String(r.outcome_status || ""))) strategySuccess[k].s += 1;
    const d = Number(r.days_to_payment);
    if (Number.isFinite(d) && d >= 0) {
      if (!strategyDays[k]) strategyDays[k] = [];
      strategyDays[k].push(d);
    }
  });
  const bestStrategy = Object.entries(strategyCounts).sort((a,b)=>b[1]-a[1])[0]?.[0] || "Auto";

  const strategySuccessRates = {};
  for (const [k,v] of Object.entries(strategySuccess)) strategySuccessRates[k] = v.n ? (v.s / v.n) : 0;
  const avgDaysByStrategy = {};
  for (const [k,vals] of Object.entries(strategyDays)) avgDaysByStrategy[k] = vals.length ? (vals.reduce((a,b)=>a+b,0) / vals.length) : null;
  const fastestStrategy = Object.entries(avgDaysByStrategy)
    .filter(([,v]) => Number.isFinite(v) && v >= 0)
    .sort((a,b)=>a[1]-b[1])[0]?.[0] || bestStrategy;

  const denialReasons = {};
  rows.forEach(r => {
    const k = String(r.denial_reason || "unknown") || "unknown";
    denialReasons[k] = (denialReasons[k] || 0) + 1;
  });
  const mostCommonDenial = Object.entries(denialReasons).sort((a,b)=>b[1]-a[1])[0]?.[0] || "unknown";

  return {
    total_cases: rows.length,
    appeal_success_rate: appealSuccessRate,
    negotiation_success_rate: negotiationSuccessRate,
    avg_days_to_payment: avgDays,
    avg_recovered_pct: avgRecoveredPct,
    best_strategy: bestStrategy,
    fastest_strategy: fastestStrategy,
    most_common_denial_reason: mostCommonDenial,
    strategy_success_rates: strategySuccessRates,
    denial_reason_patterns: denialReasons,
    avg_days_by_strategy: avgDaysByStrategy
  };
}

function computeRecoveryTimeline({ payer, strategy_profile, historicalOutcomes=[] }={}){
  const rows = (historicalOutcomes || []).filter(r =>
    String(r.payer || '').trim().toLowerCase() === String(payer || '').trim().toLowerCase() &&
    (!strategy_profile || strategy_profile === 'Auto' || String(r.strategy_profile_used || 'Auto') === String(strategy_profile))
  );
  const dayVals = rows.map(r => Number(r.days_to_payment)).filter(v => Number.isFinite(v) && v >= 0);
  const estimatedDays = dayVals.length ? (dayVals.reduce((s,v)=>s+v,0) / dayVals.length) : null;
  const within30 = dayVals.length ? (dayVals.filter(v => v <= 30).length / dayVals.length) : 0;
  const within60 = dayVals.length ? (dayVals.filter(v => v <= 60).length / dayVals.length) : 0;
  return {
    estimated_days_to_payment: estimatedDays,
    probability_payment_30_days: within30,
    probability_payment_60_days: within60
  };
}
function getAgentTasks(org_id){
  return readJSON(FILES.agent_tasks, []).filter(t => !org_id || t.org_id === org_id);
}

function saveAgentTasks(all){
  writeJSON(FILES.agent_tasks, Array.isArray(all) ? all : []);
}

function upsertAgentTask(task){
  const all = readJSON(FILES.agent_tasks, []);
  const now = nowISO();
  const ix = all.findIndex(t => t.org_id === task.org_id && t.billed_id === task.billed_id && t.stage_type === task.stage_type && String(t.status || '') !== 'closed');
  if (ix >= 0) {
    all[ix] = { ...all[ix], ...task, updated_at: now };
    writeJSON(FILES.agent_tasks, all);
    return all[ix];
  }
  const rec = {
    task_id: task.task_id || uuid(),
    org_id: task.org_id,
    billed_id: task.billed_id,
    stage_type: task.stage_type,
    status: task.status || 'queued',
    priority: Number(task.priority || 0),
    created_at: now,
    updated_at: now,
    last_run_at: task.last_run_at || null,
    notes: String(task.notes || ''),
    missing_docs: Array.isArray(task.missing_docs) ? task.missing_docs : [],
    next_actions: Array.isArray(task.next_actions) ? task.next_actions : [],
    recommended_next_step: String(task.recommended_next_step || ""),
    risk_level: String(task.risk_level || "MEDIUM"),
    estimated_value: Number(task.estimated_value || 0)
  };
  all.push(rec);
  writeJSON(FILES.agent_tasks, all);
  return rec;
}

function markTask(task_id, patch){
  const all = readJSON(FILES.agent_tasks, []);
  const ix = all.findIndex(t => t.task_id === task_id);
  if (ix < 0) return null;
  all[ix] = { ...all[ix], ...(patch || {}), updated_at: nowISO() };
  writeJSON(FILES.agent_tasks, all);
  return all[ix];
}

function computeMissingDocsForWorkspace(ws, stageType){
  const required = stageType === 'negotiation' ? ['eob_era', 'claim_form'] : ['denial_letter', 'eob_era', 'claim_form'];
  return required.filter(k => !packetHasKey(ws, k));
}

function computeNextActions(stageType, hasContractRule, missingDocs, score){
  const actions = [];
  const miss = Array.isArray(missingDocs) ? missingDocs : [];
  if (miss.includes('eob_era')) actions.push('Upload EOB/ERA');
  if (miss.includes('denial_letter')) actions.push('Upload Denial Letter');
  if (miss.includes('claim_form')) actions.push('Upload Claim Form / Itemized Bill');
  if (!hasContractRule) actions.push('Add Contract Rule');
  if (Number(score?.probability || 0) < 60) actions.push('Review argument length');
  actions.push('Submit via portal/fax/mail');
  actions.push('Set follow-up due date (default +14 days)');
  return Array.from(new Set(actions));
}

function shouldLockPacket(ws, stageType){
  const channel = stageType === 'negotiation' ? 'negotiation' : 'appeal';
  const ch = ws?.[channel] || {};
  if (ch.auto_generated === true && ch.user_modified === true) return true;
  return false;
}

function enqueueRecoveryTasksForOrg(org_id){
  if (!org_id) return 0;
  const billedAll = readJSON(FILES.billed, []);
  const ctx = buildClaimContext(org_id);
  let n = 0;
  for (const claim of billedAll) {
    if (claim.org_id !== org_id) continue;
    const d = evaluateClaimDerived(claim, ctx);
    if (!['Denied','Underpaid'].includes(String(d.lifecycleStage || ''))) continue;
    const stage_type = d.lifecycleStage === 'Denied' ? 'appeal' : 'negotiation';
    const base = stage_type === 'appeal' ? 90 : 80;
    const prio = base + Math.min(10, Math.floor(num(d.atRiskAmount || d.underpaidAmount || 0) / 1000));
    upsertAgentTask({ org_id, billed_id: claim.billed_id, stage_type, status: 'queued', priority: prio, notes: 'Enqueued from lifecycle detection' });
    n += 1;
  }
  return n;
}

function runRecoveryAgentTick(org_id){
  if (!org_id) return 0;
  const all = readJSON(FILES.agent_tasks, []);
  const openStates = new Set(['queued','running','waiting_docs','ready_for_review']);
  const work = all
    .filter(t => t.org_id === org_id && openStates.has(String(t.status || '')))
    .sort((a,b) => Number(b.priority || 0) - Number(a.priority || 0))
    .slice(0, 10);
  if (!work.length) return 0;

  const billedAll = readJSON(FILES.billed, []);
  const ctx = buildClaimContext(org_id);
  let processed = 0;

  for (const task of work) {
    const stageType = task.stage_type === 'negotiation' ? 'negotiation' : 'appeal';
    const claim = billedAll.find(b => b.org_id === org_id && b.billed_id === task.billed_id);
    if (!claim) { markTask(task.task_id, { status: 'closed', notes: 'Claim not found' }); continue; }

    markTask(task.task_id, { status: 'running', last_run_at: nowISO() });
    const d = evaluateClaimDerived(claim, ctx);
    const ws = ensureAgentWorkspace(org_id, claim);
    ensurePacketSections(ws, claim);
    const eobText = `
Paid: ${formatMoneyUI(d.paidAmount)}
Expected: ${d.expectedInsurance != null ? formatMoneyUI(d.expectedInsurance) : "Not Available"}
Variance: ${formatMoneyUI(d.underpaidAmount)}

Payer reimbursement does not align with expected contract terms.
`.trim();
    if (!String(ws?.negotiation?.packet_sections?.eob_era || "").trim()) {
      ws.negotiation.packet_sections.eob_era = eobText;
    }
    if (!String(ws?.appeal?.packet_sections?.eob_era || "").trim()) {
      ws.appeal.packet_sections.eob_era = eobText;
    }

    const billed = formatMoneyUI(d.billedAmount);
    const expected = d.expectedInsurance != null ? formatMoneyUI(d.expectedInsurance) : "Not Available";
    const paid = formatMoneyUI(d.paidAmount);
    const variance = formatMoneyUI(d.underpaidAmount);
    const reasoningText = `
Based on the contracted reimbursement terms between the provider and ${claim.payer || "the payer"}, 
the payment posted for this claim does not align with the expected allowed amount.

Billed amount: ${billed}  
Expected allowed: ${expected}  
Paid amount: ${paid}  

This results in a variance of ${variance}. We respectfully request 
review and adjustment in accordance with the payer agreement.
`.trim();
    if (!String(ws?.negotiation?.packet_sections?.variance_explanation || "").trim()) {
      ws.negotiation.packet_sections.variance_explanation = reasoningText;
    }
    if (!String(ws?.appeal?.packet_sections?.argument || "").trim()) {
      ws.appeal.packet_sections.argument = reasoningText;
    }

    const actionText = `
- Recalculate reimbursement per contract terms  
- Remit corrected payment and ERA  
- Confirm adjustment timeline  
`.trim();
    if (!String(ws?.negotiation?.packet_sections?.requested_action || "").trim()) {
      ws.negotiation.packet_sections.requested_action = actionText;
    }
    if (!String(ws?.appeal?.packet_sections?.requested_action || "").trim()) {
      ws.appeal.packet_sections.requested_action = actionText;
    }

    const contract = findContractForClaim(org_id, claim);
    let contractText = "";
    if (contract) {
      if (contract.allowed_percent) {
        contractText = `Allowed: ${contract.allowed_percent}% of billed`;
      } else if (contract.allowed_amount) {
        contractText = `Allowed: $${contract.allowed_amount}`;
      } else {
        contractText = "Contract found (details available)";
      }
    }
    if (contract && !String(ws?.negotiation?.packet_sections?.contract_excerpt || "").trim()) {
      ws.negotiation.packet_sections.contract_excerpt = contractText;
    }
    if (contract && !String(ws?.appeal?.packet_sections?.contract_excerpt || "").trim()) {
      ws.appeal.packet_sections.contract_excerpt = contractText;
    }

    if (!ws[stageType]?.auto_generated && !shouldLockPacket(ws, stageType)) {
      autoDraftWorkspaceForClaim(org_id, claim, d, ctx);
      ws[stageType] = ws[stageType] || {};
      ws[stageType].auto_generated = true;
      ws[stageType].generated_at = nowISO();
    }

    const denialReasonKey = normalizeDenialReasonKey(ws.outcome?.denial_reason || claim.denial_reason || claim.issue_reason || '');
    const hasContractRule = !!contract;
    const baseline = computeHistoricalBaselines(org_id, claim.payer || '', stageType, denialReasonKey);
    const bestStrategy = computeStrategySuccessByProfile(org_id, claim.payer || '', stageType, denialReasonKey);
    const payerIntel = computePayerBehaviorIntelligence(org_id, claim.payer || '');
    const packetSections = ws[stageType]?.packet_sections || (stageType === 'negotiation' ? defaultNegotiationPacketSections() : defaultAppealPacketSections());
    const packetFeatures = extractPacketFeatures({
      argumentText: stageType === 'negotiation' ? packetSections.variance_explanation : packetSections.argument,
      requestedActionText: packetSections.requested_action,
      attachmentsState: {
        hasDenialLetter: packetHasKey(ws, 'denial_letter'),
        hasEob: packetHasKey(ws, 'eob_era'),
        hasClaimForm: packetHasKey(ws, 'claim_form'),
        hasMedicalRecords: packetHasKey(ws, 'medical_records')
      },
      hasContract: hasContractRule
    });
    const score = computeDeterministicScore({
      stageType,
      billedAmount: num(d.billedAmount),
      paidAmount: num(d.paidAmount),
      atRiskAmount: num(d.atRiskAmount),
      requestedAmount: stageType === 'negotiation' ? num(packetSections.requested_amount || d.underpaidAmount || 0) : num(d.atRiskAmount || d.underpaidAmount || 0),
      payer: claim.payer || '',
      denialReasonKey,
      hasContractRule,
      strategyProfile: ws[stageType]?.strategy_profile || 'Auto',
      packetFeatures,
      baselines: baseline,
      strategyHistoryBest: bestStrategy,
      payerIntel,
      argumentText: stageType === 'negotiation' ? packetSections.variance_explanation : packetSections.argument
    });
    const timeline = computeRecoveryTimeline({ payer: claim.payer || '', strategy_profile: ws[stageType]?.strategy_profile || 'Auto', historicalOutcomes: loadWorkspaceOutcomes(org_id) });

    ws[stageType] = ws[stageType] || {};
    if (String(ws[stageType].strategy_profile || 'Auto') === 'Auto' && score.strategyRecommended) ws[stageType].strategy_profile = score.strategyRecommended;

    const missingDocs = computeMissingDocsForWorkspace(ws, stageType);
    const nextActions = computeNextActions(stageType, hasContractRule, missingDocs, score);
    const nextStatus = missingDocs.length ? 'waiting_docs' : 'ready_for_review';
    const riskLevel = num(score.probability) < 45 ? 'HIGH' : (num(score.probability) < 70 ? 'MEDIUM' : 'LOW');

    saveAgentWorkspace(org_id, ws);
    markTask(task.task_id, {
      missing_docs: missingDocs,
      next_actions: nextActions,
      recommended_next_step: nextActions[0] || 'Review packet and proceed',
      risk_level: riskLevel,
      estimated_value: Number(num(score.estRecovery)),
      status: nextStatus,
      last_run_at: nowISO(),
      notes: `Probability ${Math.round(num(score.probability))}% | Est ${formatMoneyUI(num(score.estRecovery))} | Timeline ${formatNumberUI(num(timeline.estimated_days_to_payment || 0),1)} days`
    });

    addAgentMessage(org_id, {
      message_id: uuid(),
      workspace_id: ws.workspace_id,
      billed_id: claim.billed_id,
      role: 'agent',
      channel: stageType,
      content: `AI Agent updated workspace: status ${nextStatus}, probability ${Math.round(num(score.probability))}%, est recovery ${formatMoneyUI(num(score.estRecovery))}, missing docs: ${missingDocs.join(', ') || 'none'}.`,
      created_at: nowISO()
    });
    processed += 1;
  }
  return processed;
}

function computeHistoricalBaselines(org_id, payer, stageType, denialReasonKey){
  const rows = loadWorkspaceOutcomes(org_id).filter(r =>
    String(r.payer || "").trim().toLowerCase() === String(payer || "").trim().toLowerCase() &&
    String(r.stage_type || "") === String(stageType || "")
  );
  const drk = normalizeDenialReasonKey(denialReasonKey);
  let scoped = rows.filter(r => normalizeDenialReasonKey(r.denial_reason) === drk);
  if (scoped.length < 3) scoped = rows;
  if (!scoped.length) return null;
  const successSet = new Set(["approved","partial","paid_in_full"]);
  const successRows = scoped.filter(r => successSet.has(String(r.outcome_status || "")));
  const successRate = scoped.length ? (successRows.length / scoped.length) : 0;
  const recoveredPcts = successRows
    .map(r => {
      const req = num(r.requested_amount);
      const rec = num(r.recovered_amount);
      return req > 0 ? (rec / req) : null;
    })
    .filter(v => v != null && isFinite(v));
  const avgRecoveredPct = recoveredPcts.length ? recoveredPcts.reduce((s,v)=>s+v,0) / recoveredPcts.length : null;
  const dayVals = scoped.map(r => Number(r.days_to_payment)).filter(v => Number.isFinite(v) && v >= 0);
  const avgDaysToPayment = dayVals.length ? dayVals.reduce((s,v)=>s+v,0) / dayVals.length : null;
  return { n: scoped.length, successRate, avgRecoveredPct, avgDaysToPayment };
}

function computeStrategySuccessByProfile(org_id, payer, stageType, denialReasonKey){
  const rows = loadWorkspaceOutcomes(org_id).filter(r =>
    String(r.payer || "").trim().toLowerCase() === String(payer || "").trim().toLowerCase() &&
    String(r.stage_type || "") === String(stageType || "")
  );
  const drk = normalizeDenialReasonKey(denialReasonKey);
  const scoped = rows.filter(r => normalizeDenialReasonKey(r.denial_reason) === drk);
  const useRows = scoped.length >= 3 ? scoped : rows;
  const successSet = new Set(["approved","partial","paid_in_full"]);
  const by = {};
  for (const r of useRows){
    const profile = String(r.strategy_profile_used || "Auto") || "Auto";
    if (!by[profile]) by[profile] = { n: 0, s: 0 };
    by[profile].n += 1;
    if (successSet.has(String(r.outcome_status || ""))) by[profile].s += 1;
  }
  let best = null;
  for (const [k,v] of Object.entries(by)){
    if (v.n < 2) continue;
    const rate = v.s / v.n;
    if (!best || rate > best.rate || (rate === best.rate && v.n > best.n)) best = { profile:k, rate, n:v.n };
  }
  return best;
}

function computeDeterministicScore(inputs){
  const stageType = String(inputs.stageType || "appeal");
  const requestedAmount = Math.max(0, num(inputs.requestedAmount || 0));
  const atRiskAmount = Math.max(0, num(inputs.atRiskAmount || 0));
  const strategyProfile = String(inputs.strategyProfile || "Auto");
  const f = inputs.packetFeatures || {};
  const baselines = inputs.baselines;
  const argumentText = String(inputs.argumentText || "");
  const strategySuccessRates = inputs.payerIntel?.strategy_success_rates || {};

  let probability = 55;
  let confidence = "Low";
  if (baselines && baselines.n >= 5){ probability = num(baselines.successRate) * 100; confidence = "High"; }
  else if (baselines && baselines.n >= 3){ probability = num(baselines.successRate) * 100; confidence = "Medium"; }

  if (f.hasDenialLetter) probability += 10;
  if (f.hasEob) probability += 10;
  if (f.hasClaimForm) probability += 5;
  if (f.hasContractCitation) probability += 8;
  if (f.hasPolicyCitation) probability += 6;
  if (f.hasMedicalRecords) probability += 5;
  if (stageType === "appeal" && !f.hasDenialLetter) probability -= 15;
  if (stageType === "appeal" && !f.hasEob) probability -= 12;
  if (!f.hasClaimForm) probability -= 10;
  if (!inputs.hasContractRule && strategyProfile === "Contractual") probability -= 12;

  const effective = strategyProfile === "Auto" ? "Auto" : strategyProfile;
  const appealGood = ["Regulatory","Contractual","Clinical"];
  const negotiationGood = ["Contractual","Collaborative"];
  if ((stageType === "appeal" && appealGood.includes(effective)) || (stageType === "negotiation" && negotiationGood.includes(effective))) probability += 6;
  if (num(f.argumentLength) < 200) probability -= 8;
  if (!f.hasClearAsk) probability -= 8;

  // Phase 2: argument quality signals
  const hasMedicalNecessity = /medical necessity|clinically appropriate|clinical indication/i.test(argumentText);
  const hasContractRef = /contract|fee schedule|allowed amount|reimbursement|agreement/i.test(argumentText);
  const hasCodeMention = /CPT|ICD|HCPCS/i.test(argumentText);
  let argument_quality_score = 40;
  argument_quality_score += hasMedicalNecessity ? 15 : 0;
  argument_quality_score += hasContractRef ? 15 : 0;
  argument_quality_score += hasCodeMention ? 10 : 0;
  argument_quality_score += num(f.completenessScore || 0) * 0.2;
  argument_quality_score = Math.max(0, Math.min(100, Math.round(argument_quality_score)));
  if (argument_quality_score >= 75) probability += 4;
  else if (argument_quality_score < 45) probability -= 6;

  probability = Math.max(5, Math.min(95, Math.round(probability)));

  let estRecovery = 0;
  if (baselines && Number.isFinite(num(baselines.avgRecoveredPct)) && num(baselines.avgRecoveredPct) > 0) {
    estRecovery = requestedAmount * num(baselines.avgRecoveredPct);
  } else {
    estRecovery = Math.min(atRiskAmount || requestedAmount, requestedAmount || atRiskAmount) * (probability / 100);
  }

  const alerts = [];
  if (stageType === "appeal" && !f.hasDenialLetter) alerts.push("Missing Denial Letter for appeal packet.");
  if (stageType === "appeal" && !f.hasEob) alerts.push("Missing EOB/ERA for appeal packet.");
  if (!f.hasClaimForm) alerts.push("Missing claim form/itemized bill.");
  if (!inputs.hasContractRule) alerts.push("Contract rule missing - add contract rule in Reimbursement Contracts");
  if (num(f.argumentLength) < 200) alerts.push("Argument narrative is short; add clinical/contract rationale.");
  if (!f.hasClearAsk) alerts.push("Requested action is unclear; include a specific ask.");
  if (!inputs.hasContractRule && strategyProfile === "Contractual") alerts.push("Contractual strategy selected but no contract rule found.");

  let strategyRecommended = "Collaborative";
  if (inputs.strategyHistoryBest && inputs.strategyHistoryBest.profile) strategyRecommended = inputs.strategyHistoryBest.profile;
  else if (stageType === "appeal") {
    const dr = String(inputs.denialReasonKey || "").toLowerCase();
    strategyRecommended = (dr.includes("timely") || dr.includes("medical_necessity") || dr.includes("medical necessity")) ? "Regulatory" : "Contractual";
  } else {
    strategyRecommended = inputs.hasContractRule ? "Contractual" : "Collaborative";
  }

  if (inputs.payerIntel && inputs.payerIntel.best_strategy) {
    strategyRecommended = String(inputs.payerIntel.best_strategy);
  }

  // Phase 2 smart strategy switching
  let strategySwitchSuggestion = "";
  if (probability < 50 && strategySuccessRates && Object.keys(strategySuccessRates).length) {
    const current = String(strategyProfile || 'Auto');
    const currentRate = num(strategySuccessRates[current]);
    const better = Object.entries(strategySuccessRates)
      .sort((a,b)=>num(b[1])-num(a[1]))
      .find(([k,v]) => k !== current && num(v) > currentRate + 0.05);
    if (better) {
      strategyRecommended = better[0];
      strategySwitchSuggestion = `Switch from ${current} → ${better[0]}`;
    }
  }

  return { probability, confidence, estRecovery, alerts, strategyRecommended, argument_quality_score, strategySwitchSuggestion };
}

function renderWorkspaceTabs(billed_id, activeTab){
  const mk = (key, label) => `<a class="btn ${activeTab===key?"":"secondary"}" href="${workspacePagePath(billed_id, key)}">${label}</a>`;
  return `<div style="display:flex;gap:8px;flex-wrap:wrap;margin:10px 0 14px;">${mk("appeal","Appeal Draft")}${mk("negotiation","Negotiation Draft")}${mk("packet","Packet Builder")}${mk("activity","Activity")}</div>`;
}

function storeWorkspaceUpload(org_id, file){
  const dir = path.join(UPLOADS_DIR, org_id, "agent_workspace");
  ensureDir(dir);
  const clean = String(file.filename || "upload.bin").replace(/[^a-zA-Z0-9._-]/g, "_");
  const stored = `${Date.now()}_${uuid()}_${clean}`;
  const storedPath = path.join(dir, stored);
  fs.writeFileSync(storedPath, file.buffer);
  return { filename: clean, stored_path: storedPath };
}

function claimFinancialSnapshot(derived, claim){
  const underpaidAmount = Math.max(0, Number(derived?.underpaidAmount || 0));
  const expectedInsuranceText = (derived?.expectedInsurance != null && derived?.expectedInsurance !== "")
    ? formatMoneyUI(derived.expectedInsurance)
    : "Not Available (No Contract Match)";
  return [
    `Billed: ${formatMoneyUI(derived?.billedAmount || claim?.amount_billed || 0)}`,
    `Expected Insurance: ${expectedInsuranceText}`,
    `Paid by Payer: ${formatMoneyUI(derived?.paidAmount || claim?.paid_amount || 0)}`,
    `Underpaid Amount: ${formatMoneyUI(underpaidAmount)}`,
    `Patient Follow-Up Remaining: ${formatMoneyUI(derived?.patientBalanceRemaining || 0)}`,
  ].join("\n");
}

function packetHeaderFromSettings(orgSettings, orgRecord, claim){
  const identity = (orgSettings || {}).identity || {};
  const orgName = getOrgDisplayName(orgSettings, orgRecord);
  const mailing = formatOrgMailingBlock(orgSettings);
  const contact = [
    identity.phone ? `Phone: ${identity.phone}` : "",
    identity.fax ? `Fax: ${identity.fax}` : "",
    `Date: ${nowISO().slice(0,10)}`,
    `Claim #: ${claim?.claim_number || "N/A"}`
  ].filter(Boolean).join("\n");
  return [orgName, mailing, contact].filter(Boolean).join("\n");
}

function signatureFromSettings(orgSettings, orgRecord){
  const defaults = getLetterDefaults(orgSettings);
  return String(defaults.signature_block || "").trim() || getOrgDisplayName(orgSettings, orgRecord);
}

function applyDefaultTone(text, tone, type){
  let out = String(text || "");
  const t = String(tone || "Professional");
  if (t === "Firm") {
    out = out.replace("We request", "We formally request");
    out = out.replace("We are submitting", "We are formally submitting");
  }
  if (t === "Aggressive") {
    out = out.replace("We request", "We demand immediate");
    out = out.replace("Please overturn", "You must overturn");
    if (type === "negotiation") out = out.replace("We are submitting", "We require prompt correction of");
  }
  return out;
}

function agentDraftFromRules({ type, claim, derived, appealCase, negotiationCase, orgProfile, practiceSettings, orgSettings }){
  const dos = claim?.dos || claim?.date_of_service || "N/A";
  const underpaidAmount = Math.max(0, Number(derived?.underpaidAmount || 0));
  const attachmentLine = "Attachments included: denial notice/EOB, claim form, relevant records, contract excerpts, and supporting notes.";
  const opening = `${packetHeaderFromSettings(orgSettings, orgProfile, claim)}

Re: Claim #${claim?.claim_number || "N/A"} | Payer: ${claim?.payer || "Unknown"} | DOS: ${dos}`;
  const financials = claimFinancialSnapshot(derived, claim);
  if (type === "appeal") {
    const denialRef = appealCase ? `Denial Case ID: ${appealCase.case_id || "N/A"}` : "Denial Case ID: N/A";
    const draft = `${opening}
${denialRef}

To Appeals Department,

We request reconsideration and reprocessing of the denied claim above. Based on the submitted documentation and treatment details, this claim meets plan requirements and medical necessity standards. Please overturn the denial and issue payment according to applicable plan benefits and contracted terms.

Claim Financial Snapshot
${financials}

Requested Action
- Reprocess claim and reverse denial determination.
- Apply in-network/contracted benefits where applicable.
- Provide written rationale and policy citation if any portion remains denied.

${attachmentLine}

Thank you for your prompt review. Please contact our office with any additional requirements.

Sincerely,
${signatureFromSettings(orgSettings, orgProfile)}`.trim();
    return draft;
  }
  const negotiationIdLine = negotiationCase ? `Negotiation ID: ${negotiationCase.negotiation_id || "N/A"}` : "Negotiation ID: N/A";
  const draft = `${opening}
${negotiationIdLine}

To Provider Contracting / Claims Adjustment Team,

We are submitting this underpayment variance request for review. The paid amount does not align with expected reimbursement based on our contracted terms and claim details.

Claim Financial Snapshot
${financials}

Requested Action
- Recalculate reimbursement per contract terms and remit corrected payment.
- Requested amount: ${formatMoneyUI(underpaidAmount)}
- Confirm adjustment details and remittance timeline.

${attachmentLine}

We appreciate your expedited review and response.

Sincerely,
${signatureFromSettings(orgSettings, orgProfile)}`.trim();
  return draft;
}

function applyAgentInstructionToDraft(draftText, instruction, channel){
  const txt = String(draftText || "");
  const ins = String(instruction || "").trim();
  if (!ins) return txt;
  let next = txt;
  const lower = ins.toLowerCase();
  if (lower.includes("stronger") || lower.includes("firm")) {
    next = next.replace("We request", "We formally request");
  }
  if (lower.includes("shorter") || lower.includes("concise")) {
    next = next.replace(/\n\nThank you for your prompt review\.[\s\S]*$/m, "\n\nThank you for your review.");
  }
  next += `\n\nRequested edits (${channel}):\n- ${ins}`;
  return next;
}

function renderTemplate(templateBody, claim){
  return String(templateBody || "")
    .replace(/{{CLAIM_NUMBER}}/g, claim.claim_number || "")
    .replace(/{{PAYER}}/g, claim.payer || "")
    .replace(/{{DOS}}/g, claim.dos || "")
    .replace(/{{BILLED}}/g, formatMoneyUI(claim.amount_billed || 0))
    .replace(/{{EXPECTED}}/g, formatMoneyUI(claim.expected_insurance || 0))
    .replace(/{{PAID}}/g, formatMoneyUI(claim.paid_amount || 0));
}

function generateDraftUsingTemplateOrRules({ org_id, type, claim, derived, appealCase, negotiationCase, ws }){
  const orgSettings = getOrgSettings(org_id);
  const letterDefaults = getLetterDefaults(orgSettings);
  const orgRecord = getOrg(org_id);
  const header = packetHeaderFromSettings(orgSettings, orgRecord, claim);
  const signature = signatureFromSettings(orgSettings, orgRecord);
  const applyChannelDefaults = (text) => {
    let draft = String(text || "").trim();
    if (type === "appeal") {
      if (letterDefaults.appeal_opening) draft = `${letterDefaults.appeal_opening}\n\n${draft}`;
      if (letterDefaults.appeal_footer) draft = `${draft}\n\n${letterDefaults.appeal_footer}`;
    } else {
      if (letterDefaults.negotiation_opening) draft = `${letterDefaults.negotiation_opening}\n\n${draft}`;
      if (letterDefaults.negotiation_footer) draft = `${draft}\n\n${letterDefaults.negotiation_footer}`;
    }
    return applyDefaultTone(draft, letterDefaults.appeal_tone, type);
  };

  const selectedTemplateId = type === "appeal" ? ws?.appeal?.template_id : ws?.negotiation?.template_id;
  const template = getTemplateById(org_id, selectedTemplateId);
  const financials = claimFinancialSnapshot(derived, claim);
  if (template && String(template.body || "").trim()) {
    const rendered = renderTemplate(template.body, claim).trim();
    return applyChannelDefaults(`${header}

${rendered}

Claim Financial Snapshot
${financials}

Sincerely,
${signature}`);
  }
  if (type === "negotiation") {
    const variance = Number(derived?.underpaidAmount || 0);
    const negotiationNarrative = `Based on the contracted reimbursement terms between the provider and ${claim?.payer || "the payer"}, the payment posted for this claim does not align with the expected allowed amount.

Billed amount: ${formatMoneyUI(derived?.billedAmount || 0)}
Expected allowed: ${formatMoneyUI(derived?.expectedInsurance || 0)}
Paid amount: ${formatMoneyUI(derived?.paidAmount || 0)}

This creates a variance of ${formatMoneyUI(variance)}.

We respectfully request review and adjustment of the allowed amount in accordance with the provider agreement and applicable reimbursement methodology.

Please reprocess the claim and issue corrected payment.`;
    return applyChannelDefaults(negotiationNarrative);
  }
  const rulesDraft = agentDraftFromRules({ type, claim, derived, appealCase, negotiationCase, orgProfile: orgRecord, practiceSettings: getPracticeSettings(org_id), orgSettings });
  return applyChannelDefaults(rulesDraft);
}



function financialSummaryFromClaim(derived, claim){
  return claimFinancialSnapshot(derived, claim);
}

function buildAttachmentsIndex(ws){
  const attachments = Array.isArray(ws?.attachments) ? ws.attachments : [];

  if (!attachments.length) {
    return "No supporting documents uploaded.";
  }

  const order = [
    "denial_letter",
    "eob_era",
    "claim_form",
    "contract_excerpt",
    "payer_policy",
    "lmn",
    "office_notes",
    "labs_imaging"
  ];

  const sorted = attachments.sort((a,b)=>{
    return order.indexOf(a.doc_key) - order.indexOf(b.doc_key);
  });

  return sorted.map(a=>{
    return `- ${workspaceDocLabel(a.doc_key)}: ${a.filename}`;
  }).join("\n");
}

function workspaceDocLabel(key){
  const labels = {
    denial_letter: "Denial Letter",
    eob_era: "EOB / ERA",
    claim_form: "Claim Form / Itemized Bill",
    lmn: "Letter of Medical Necessity",
    office_notes: "Office / Operative Notes",
    labs_imaging: "Labs / Imaging",
    contract_excerpt: "Contract Excerpt / Allowed Rule",
    payer_policy: "Payer Policy Citation",
    medical_records: "Medical Records"
  };
  return labels[key] || key;
}

function workspaceRequiredDocConfig(channel){
  const base = [
    { key:"eob_era", label:"EOB / ERA", required:true },
    { key:"claim_form", label:"Claim Form / Itemized Bill", required:true },
    { key:"contract_excerpt", label:"Contract Excerpt / Allowed Rule", required:false },
    { key:"payer_policy", label:"Payer Policy Citation", required:false },
    { key:"lmn", label:"Letter of Medical Necessity", required:false },
    { key:"office_notes", label:"Office / Operative Notes", required:false },
    { key:"labs_imaging", label:"Labs / Imaging", required:false }
  ];
  if (channel === "appeal") base.unshift({ key:"denial_letter", label:"Denial Letter", required:true });
  return base;
}

function workspaceFindAttachmentByPacketKey(ws, key){
  const item = getWorkspacePacketItem(ws, key);
  if (item && item.attachment_id) {
    const found = (ws.attachments || []).find(a => String(a.attachment_id || "") === String(item.attachment_id || ""));
    if (found) return found;
  }
  return null;
}

function workspaceUpsertPacketItem(ws, key, patch){
  ensureWorkspacePacket(ws);
  const groups = ["required_appeal","clinical_support","contract_policy"];
  for (const g of groups){
    const arr = ws.packet[g] || [];
    const idx = arr.findIndex(x => x.key === key);
    if (idx >= 0){
      arr[idx] = { ...arr[idx], ...(patch || {}) };
      ws.packet[g] = arr;
      ws.packet.completeness = computePacketCompleteness(ws);
      return arr[idx];
    }
  }
  return null;
}

function workspaceAttachmentKindForDocKey(key){
  const map = {
    denial_letter: "denial_letter",
    eob_era: "eob",
    claim_form: "claim_form",
    lmn: "lmn",
    office_notes: "medical_records",
    labs_imaging: "medical_records",
    contract_excerpt: "contract",
    payer_policy: "policy",
    medical_records: "medical_records"
  };
  return map[key] || "supporting";
}

function workspaceEnhancedCompleteness(ws, channel){
  ensureWorkspacePacket(ws);
  ensurePacketSections(ws);
  const docs = workspaceRequiredDocConfig(channel);
  const totalRequired = docs.filter(d => d.required).length;
  const haveRequired = docs.filter(d => d.required && packetHasKey(ws, d.key)).length;

  const sectionKey = packetNarrativeKey(channel);
  const sections = channel === "negotiation"
    ? ["header","claim_summary","financial_summary","variance_explanation","requested_amount","requested_action","attachments_index","signature"]
    : ["header","claim_summary","financial_summary","argument","requested_action","attachments_index","signature"];

  const packetSections = ws[channel]?.packet_sections || {};
  const filledSections = sections.filter(k => String(packetSections[k] || "").trim()).length;

  const total = totalRequired + sections.length;
  const complete = haveRequired + filledSections;
  const pct = total ? Math.round((complete / total) * 100) : 0;

  return {
    total,
    complete,
    pct,
    requiredMissing: docs.filter(d => d.required && !packetHasKey(ws, d.key)),
    docs,
    sectionKey
  };
}

function computeWorkspaceQuickScore(ws, claim, derived, channel){
  const completeness = workspaceEnhancedCompleteness(ws, channel);
  const hasEOB = packetHasKey(ws, "eob_era");
  const hasClaim = packetHasKey(ws, "claim_form");
  const hasDenial = packetHasKey(ws, "denial_letter");

  let score = 50;

  if (hasEOB) score += 10;
  if (hasClaim) score += 10;
  if (channel === "appeal" && hasDenial) score += 10;

  score += Math.round((completeness.pct || 0) * 0.2);

  score = Math.max(10, Math.min(95, score));

  const estimatedRecovery = Math.round((derived?.underpaidAmount || derived?.atRiskAmount || 0) * (score / 100));

  return {
    probability: score,
    estimatedRecovery
  };
}

function renderWorkspaceIntelligence(ws, claim, derived, channel){
  const score = computeWorkspaceQuickScore(ws, claim, derived, channel);

  const riskLevel =
    score.probability >= 80 ? "High Confidence" :
    score.probability >= 60 ? "Moderate Confidence" :
    "Low Confidence";

  const drivers = [];

  if (!packetHasKey(ws,"eob_era")) drivers.push("Missing EOB");
  if (!packetHasKey(ws,"claim_form")) drivers.push("Missing claim form");
  if (channel === "appeal" && !packetHasKey(ws,"denial_letter")) drivers.push("Missing denial");

  const driverText = drivers.length
    ? `Risk Factors: ${drivers.join(", ")}`
    : "All required documents present";

  const actionSignal =
    score.probability >= 80 ? "Proceed to Submission" :
    score.probability >= 60 ? "Review Before Submitting" :
    "Improve Packet Before Submission";

  return `
    <div class="ws-intel-card">

      <div class="ws-intel-header">
        <div style="display:flex;align-items:center;gap:6px;">
          <span>📊</span>
          <span>Revenue Intelligence</span>
        </div>
      </div>

      <div class="ws-intel-main">
        <div>
          <div class="ws-intel-score">${score.probability}%</div>
          <div class="ws-intel-label">Success Probability</div>
        </div>

        <div style="text-align:right;">
          <div style="font-size:18px;font-weight:900;">
            ${formatMoneyUI(score.estimatedRecovery)}
          </div>
          <div class="ws-intel-label">Estimated Recovery</div>
        </div>
      </div>

      <div class="ws-intel-bar">
        <div class="ws-intel-bar-fill" style="width:${score.probability}%;"></div>
      </div>

      <div class="ws-intel-sub">
        ${riskLevel}
      </div>

      <div class="ws-intel-sub" style="opacity:.8;">
        ${driverText}
      </div>

      <div style="margin-top:10px;font-weight:700;">
        ${actionSignal}
      </div>

    </div>
  `;
}

