function autoDraftWorkspaceForClaim(org_id, claim, derived, claimCtx){
  if (!org_id || !claim?.billed_id) return 0;
  const ws = ensureAgentWorkspace(org_id, claim);
  ensurePacketSections(ws, claim);
  const ts = nowISO();
  const refTs = Math.max(
    new Date(claim?.paid_at || 0).getTime() || 0,
    new Date(claim?.updated_at || 0).getTime() || 0,
    new Date(claim?.created_at || 0).getTime() || 0
  );
  const currentDerived = derived && derived.lifecycleStage ? derived : evaluateClaimDerived(claim, claimCtx || buildClaimContext(org_id));
  const casesAll = readJSON(FILES.cases, []).filter(c => c.org_id === org_id);
  const appealCase = claim.denial_case_id ? casesAll.find(c => c.case_id === claim.denial_case_id) : null;
  const negotiationCase = getNegotiationsByBilled(org_id, claim.billed_id).map(n=>normalizeNegotiation(n))[0] || null;
  const shouldRefresh = (draftMeta) => {
    if (!String(draftMeta?.draft_text || "").trim()) return true;
    const runTs = new Date(draftMeta?.last_run_at || draftMeta?.updated_at || 0).getTime() || 0;
    return runTs < refTs;
  };
  const stage = String(currentDerived?.lifecycleStage || "");
  const wantAppeal = stage === "Denied" || stage === "In Appeal/Negotiation";
  const wantNegotiation = stage === "Underpaid" || stage === "In Appeal/Negotiation";
  let generated = 0;
  if (wantAppeal && shouldRefresh(ws.appeal)) {
    const narrative = generateDraftUsingTemplateOrRules({ org_id, type: "appeal", claim, derived: currentDerived, appealCase, negotiationCase, ws });
    ws.appeal.packet_sections = {
      ...defaultAppealPacketSections(),
      ...(ws.appeal.packet_sections || {}),
      header: ws.appeal.packet_sections?.header || `${safeStr(getOrg(org_id)?.org_name || "Practice")} - ${nowISO().slice(0,10)} - Claim #${claim?.claim_number || "N/A"}`,
      claim_summary: ws.appeal.packet_sections?.claim_summary || `Claim #${claim?.claim_number || "N/A"} | Payer: ${claim?.payer || "Unknown"} | DOS: ${claim?.dos || "N/A"}`,
      financial_summary: financialSummaryFromClaim(currentDerived, claim),
      argument: narrative,
      requested_action: ws.appeal.packet_sections?.requested_action || `- Reverse denial determination.\n- Reprocess claim per benefits/contract.\n- Provide written rationale if denial remains.`,
      attachments_index: buildAttachmentsIndex(ws),
      signature: ws.appeal.packet_sections?.signature || (getOrg(org_id)?.org_name || "Practice")
    };
    ws.appeal = { ...(ws.appeal || {}), draft_text: ws.appeal.packet_sections.argument, updated_at: ts, last_run_at: ts, version: Number(ws.appeal?.version || 0) + 1 };
    generated += 1;
  }
  if (wantNegotiation && shouldRefresh(ws.negotiation)) {
    const narrative = generateDraftUsingTemplateOrRules({ org_id, type: "negotiation", claim, derived: currentDerived, appealCase, negotiationCase, ws });
    ws.negotiation.packet_sections = {
      ...defaultNegotiationPacketSections(),
      ...(ws.negotiation.packet_sections || {}),
      header: ws.negotiation.packet_sections?.header || `${safeStr(getOrg(org_id)?.org_name || "Practice")} - ${nowISO().slice(0,10)} - Claim #${claim?.claim_number || "N/A"}`,
      claim_summary: ws.negotiation.packet_sections?.claim_summary || `Claim #${claim?.claim_number || "N/A"} | Payer: ${claim?.payer || "Unknown"} | DOS: ${claim?.dos || "N/A"}`,
      financial_summary: financialSummaryFromClaim(currentDerived, claim),
      variance_explanation: narrative,
      requested_amount: String(ws.negotiation.packet_sections?.requested_amount || currentDerived?.underpaidAmount || ""),
      requested_action: ws.negotiation.packet_sections?.requested_action || `- Recalculate reimbursement per contract terms.\n- Remit corrected payment and ERA.\n- Confirm adjustment timeline.`,
      attachments_index: buildAttachmentsIndex(ws),
      signature: ws.negotiation.packet_sections?.signature || (getOrg(org_id)?.org_name || "Practice")
    };
    ws.negotiation = { ...(ws.negotiation || {}), draft_text: ws.negotiation.packet_sections.variance_explanation, requested_amount: Number(ws.negotiation.packet_sections.requested_amount || currentDerived?.underpaidAmount || 0), updated_at: ts, last_run_at: ts, version: Number(ws.negotiation?.version || 0) + 1 };
    generated += 1;
  }
  ws.appeal.packet_sections.attachments_index = buildAttachmentsIndex(ws);
  ws.appeal.packet_sections.financial_summary = financialSummaryFromClaim(currentDerived, claim);
  ws.negotiation.packet_sections.attachments_index = buildAttachmentsIndex(ws);
  ws.negotiation.packet_sections.financial_summary = financialSummaryFromClaim(currentDerived, claim);
  ws.negotiation.packet_sections.requested_amount = String(ws.negotiation.packet_sections.requested_amount || currentDerived?.underpaidAmount || "");
  saveAgentWorkspace(org_id, ws);
  if (generated > 0) {
    ws.status = "draft";
    saveAgentWorkspace(org_id, ws);
    addAgentMessage(org_id, { message_id: uuid(), workspace_id: ws.workspace_id, billed_id: claim.billed_id, role: "agent", channel: "general", content: "Draft auto-generated (reason: denial/payment update).", created_at: ts });
    const usage = getUsage(org_id);
    usage.monthly_ai_generations_used = Number(usage.monthly_ai_generations_used || 0) + generated;
    saveUsage(usage);
  }
  return generated;
}

function consumeAgentCredit(org_id){
  const usage = readJSON(FILES.agent_usage, []);
  const month = new Date().toISOString().slice(0,7);

  let rec = usage.find(u => u.org_id === org_id && u.month === month);
  if (!rec){
    rec = { org_id, month, used: 0 };
    usage.push(rec);
  }

  rec.used += 1;
  writeJSON(FILES.agent_usage, usage);
}

function getAgentUsage(org_id){
  const month = new Date().toISOString().slice(0,7);
  const usage = readJSON(FILES.agent_usage, []);
  return usage.find(u => u.org_id === org_id && u.month === month) || { used: 0 };
}

// ===== Pagination + Filtering Helpers =====
const PAGE_SIZE_OPTIONS = [30, 50, 100];

function clampInt(v, minV, maxV, fallback){
  const n = Number(v);
  if (!Number.isFinite(n)) return fallback;
  return Math.max(minV, Math.min(maxV, Math.floor(n)));
}

function parsePageParams(qs){
  const pageSize = clampInt(qs.pageSize || qs.per_page || 50, 30, 100, 50);
  const page = clampInt(qs.page || 1, 1, 999999, 1);
  const startIdx = (page - 1) * pageSize;
  return { page, pageSize, startIdx };
}

function buildPageNav(basePath, qsObj, page, totalPages){
  if (totalPages <= 1) return "";
  const qsBase = { ...qsObj };
  delete qsBase.page;
  const links = [];

  const prev = Math.max(1, page - 1);
  const next = Math.min(totalPages, page + 1);

  const qsPrev = new URLSearchParams({ ...qsBase, page: String(prev) }).toString();
  const qsNext = new URLSearchParams({ ...qsBase, page: String(next) }).toString();

  links.push(`<a class="btn secondary small" href="${basePath}?${qsPrev}">Prev</a>`);

  const windowSize = 7;
  let start = Math.max(1, page - Math.floor(windowSize/2));
  let end = Math.min(totalPages, start + windowSize - 1);
  start = Math.max(1, end - windowSize + 1);

  for (let p = start; p <= end; p++){
    const qsP = new URLSearchParams({ ...qsBase, page: String(p) }).toString();
    links.push(`<a href="${basePath}?${qsP}" style="margin:0 6px;${p===page?'font-weight:900;text-decoration:underline;':''}">${p}</a>`);
  }

  links.push(`<a class="btn secondary small" href="${basePath}?${qsNext}">Next</a>`);
  return `<div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-top:10px;">${links.join("")}</div>`;
}

// ===== Negotiation Status =====
const NEGOTIATION_STATUSES = [
  "Open",
  "Packet Generated",
  "Submitted",
  "In Review",
  "Counter Offered",
  "Approved (Pending Payment)",
  "Payment Received",
  "Denied",
  "Closed"
];

function normalizeNegotiation(rec){
  if (!rec) return rec;
  if (!rec.status) rec.status = "Open";
  if (!NEGOTIATION_STATUSES.includes(rec.status)) rec.status = "Open";
  if (!Array.isArray(rec.documents)) rec.documents = [];
  if (!rec.negotiation_packet) rec.negotiation_packet = {};
  if (!Array.isArray(rec.negotiation_packet.attachments)) rec.negotiation_packet.attachments = [];
  if (!rec.negotiation_packet.negotiation_letter_text) rec.negotiation_packet.negotiation_letter_text = String(rec.packet_draft || "");
  if (!rec.negotiation_packet.submitted_at) rec.negotiation_packet.submitted_at = null;
  if (!rec.negotiation_packet.exported_at) rec.negotiation_packet.exported_at = null;
  if (!rec.created_at) rec.created_at = nowISO();
  rec.updated_at = nowISO();
  rec.approved_amount = num(rec.approved_amount);
  rec.collected_amount = num(rec.collected_amount);
  rec.requested_amount = num(rec.requested_amount);
  return rec;
}

function getNegotiationsByBilled(org_id, billed_id){
  return getNegotiations(org_id).filter(n => n.billed_id === billed_id);
}

function getPayerContracts(org_id){
  return readJSON(FILES.payer_contracts, []).filter(x => x.org_id === org_id);
}

function normalizeContractText(v){
  return String(v || "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, " ");
}

function deepCollectStrings(value, out = [], seen = new Set()){
  if (value == null) return out;
  if (typeof value === "string" || typeof value === "number") {
    out.push(String(value));
    return out;
  }
  if (typeof value !== "object") return out;
  if (seen.has(value)) return out;
  seen.add(value);

  if (Array.isArray(value)) {
    for (const item of value) deepCollectStrings(item, out, seen);
    return out;
  }

  for (const [k, v] of Object.entries(value)) {
    out.push(String(k));
    deepCollectStrings(v, out, seen);
  }
  return out;
}

function deepFindFirstMatchingValue(obj, tests = []){
  if (!obj || typeof obj !== "object") return "";
  const queue = [obj];
  const seen = new Set();

  while (queue.length) {
    const cur = queue.shift();
    if (!cur || typeof cur !== "object" || seen.has(cur)) continue;
    seen.add(cur);

    if (Array.isArray(cur)) {
      for (const item of cur) queue.push(item);
      continue;
    }

    for (const [key, value] of Object.entries(cur)) {
      const keyStr = String(key || "").toLowerCase();
      const valStr = value == null ? "" : String(value).trim();

      for (const test of tests) {
        if (test(keyStr, valStr, value)) return valStr;
      }

      if (value && typeof value === "object") queue.push(value);
    }
  }

  return "";
}

function deepFindClaimProcedureValue(claim){
  const allStrings = deepCollectStrings(claim);

  for (const str of allStrings) {
    const match = String(str).match(/\b\d{5}\b/);
    if (match) return match[0];
  }

  return "";
}

function deepFindClaimPayerValue(claim){
  return deepFindFirstMatchingValue(claim, [
    (k, v) => /(payer|insurance|carrier|plan)/i.test(k) && !!v && !/\d{5}/.test(v)
  ]);
}

function deepFindClaimDiagnosisValue(claim){
  return deepFindFirstMatchingValue(claim, [
    (k, v) => /(dx|diagnosis|icd)/i.test(k) && !!v
  ]);
}

function getRawClaimPayerValue(claim){
  return (
    claim?.payer ||
    claim?.payer_name ||
    claim?.insurance_payer ||
    claim?.primary_payer ||
    claim?.plan_name ||
    claim?.plan ||
    claim?.carrier ||
    claim?.insurance_name ||
    deepFindClaimPayerValue(claim) ||
    ""
  );
}

function getClaimPayerText(claim){
  return normalizeContractText(getRawClaimPayerValue(claim));
}

function normalizeNetworkStatus(v){
  const raw = String(v || "").trim().toLowerCase();
  if (raw.includes("out")) return "Out of Network";
  return "In Network";
}

function normalizeProcedureCode(v){
  const raw = String(v || "").trim().toUpperCase();
  const m = raw.match(/\d{5}/);
  return m ? m[0] : raw.replace(/[^A-Z0-9]/g, "");
}

function normalizeDiagnosisCode(v){
  return String(v || "").trim().toUpperCase().replace(/[^A-Z0-9]/g, "");
}

function getContractProcedureCode(x){
  return normalizeProcedureCode(
    x?.procedure_code ||
    x?.cpt_code ||
    x?.cpt ||
    x?.proc_code ||
    x?.code ||
    ""
  );
}

function getRawClaimProcedureValue(claim){
  return (
    claim?.procedure_code ||
    claim?.cpt_code ||
    claim?.cpt ||
    claim?.proc_code ||
    claim?.code ||
    claim?.hcpcs ||
    claim?.service_code ||
    claim?.billing_code ||
    claim?.primary_procedure ||
    claim?.line_items?.[0]?.code ||
    claim?.services?.[0]?.cpt ||
    claim?.procedures?.[0]?.code ||
    deepFindClaimProcedureValue(claim) ||
    ""
  );
}

function getClaimProcedureCode(claim){
  return normalizeProcedureCode(getRawClaimProcedureValue(claim));
}

function getBestClaimCPT(claim){
  const candidates = [
    claim?.claim_procedure_code_normalized,
    getClaimProcedureCode(claim),
    claim?.procedure_code,
    claim?.cpt_code,
    claim?.code,
    claim?.service_code
  ];

  for (const c of candidates){
    const norm = normalizeProcedureCode(c);
    if (norm) return norm;
  }

  const allStrings = deepCollectStrings(claim);
  for (const str of allStrings){
    const match = String(str).match(/\b\d{5}\b/);
    if (match) return match[0];
  }

  return "";
}

function getRawClaimDiagnosisValue(claim){
  return (
    claim?.diagnosis_code ||
    claim?.icd10 ||
    claim?.icd10_code ||
    claim?.dx_code ||
    deepFindClaimDiagnosisValue(claim) ||
    ""
  );
}

function getClaimDiagnosisCode(claim){
  return normalizeDiagnosisCode(getRawClaimDiagnosisValue(claim));
}

function stampCanonicalClaimFields(claim){
  if (!claim || typeof claim !== "object") return claim;
  claim.claim_payer_raw = getRawClaimPayerValue(claim);
  claim.claim_procedure_code_raw = getRawClaimProcedureValue(claim);
  claim.claim_diagnosis_code_raw = getRawClaimDiagnosisValue(claim);
  claim.claim_payer_normalized = getClaimPayerText(claim);
  claim.claim_procedure_code_normalized = getClaimProcedureCode(claim);
  claim.claim_diagnosis_code_normalized = getClaimDiagnosisCode(claim);
  return claim;
}

function debugClaimAndContracts(org_id, claim, contracts){
  debugLog("Claim processed:", {
    org_id,
    claim_number: claim?.claim_number,
    payer: claim?.payer || claim?.claim_payer_normalized || "",
    billed: claim?.amount_billed || claim?.billed_amount || "",
    contract_candidates: Array.isArray(contracts) ? contracts.length : 0
  });
}

function contractMatchesClaim(contract, claim){
  if (!contract || !claim) return false;

  const contractPayer = contract.payer_name || contract.payer;
  const claimPayer = getClaimPayerText(claim);
  const contractProc = normalizeProcedureCode(contract.procedure_code);
  const claimProc = getBestClaimCPT(claim);

  if (!payerMatch(contractPayer, claimPayer)) return false;
  if (!cptMatch(contractProc, claimProc)) return false;

  return true;
}

function safeMatchContract(contract, claim){
  return contractMatchesClaim(contract, claim);
}

function cptMatch(contractCpt, claimCpt){
  if (!contractCpt || !claimCpt) return false;
  if (contractCpt === claimCpt) return true;

  const contractPrefix = contractCpt.slice(0, 3);
  const claimPrefix = claimCpt.slice(0, 3);
  if (contractPrefix === claimPrefix) return true;
  return false;
}

function payerMatch(contractPayer, claimPayer){
  if (!contractPayer || !claimPayer) return false;

  const c = String(contractPayer).toLowerCase().replace(/[^a-z0-9]/g, "");
  const p = String(claimPayer).toLowerCase().replace(/[^a-z0-9]/g, "");

  return c === p || c.includes(p) || p.includes(c);
}

function normalizeContract(c){
  const contract = c || {};
  return {
    ...contract,
    contract_id: contract.contract_id || uuid(),
    payer_name: String(contract.payer_name || contract.payer || "").trim(),
    procedure_code: getContractProcedureCode(contract),
    diagnosis_code: String(contract.diagnosis_code || "").trim(),
    expected_value: Number(contract.expected_value || contract.allowed_amount || 0),
    reimbursement_model: String(contract.reimbursement_model || "fixed_amount").trim() || "fixed_amount",
    network_status: normalizeNetworkStatus(contract.network_status || "In Network")
  };
}

// Flexible field picker (handles messy CSV headers)
function pickFirst(row, names){
  const keys = Object.keys(row || {});

  // exact match first
  for (const name of names) {
    const found = keys.find(k => String(k || "").trim().toLowerCase() === name.toLowerCase());
    if (found && row[found] != null && String(row[found]).trim() !== "") {
      return String(row[found]).trim();
    }
  }

  // fallback: partial match
  for (const name of names) {
    const found = keys.find(k => String(k || "").trim().toLowerCase().includes(name.toLowerCase()));
    if (found && row[found] != null && String(row[found]).trim() !== "") {
      return String(row[found]).trim();
    }
  }

  return "";
}

function extractCPTFromAnyField(value){
  if (!value) return "";

  const str = String(value);
  const match = str.match(/\b\d{5}\b/);
  return match ? match[0] : "";
}

function mapBilledClaimRow(row){
  const claim_number = pickFirst(row, [
    "claim_number", "claim id", "id"
  ]);

  const payer = pickFirst(row, [
    "payer", "insurance", "carrier", "plan"
  ]);

  const procedure_raw =
    pickFirst(row, ["procedure_code", "cpt", "code", "service"]) ||
    pickFirst(row, ["description", "procedure", "details"]) ||
    JSON.stringify(row);

  const procedure_code = extractCPTFromAnyField(procedure_raw);

  const amount_billed = num(
    pickFirst(row, ["amount", "billed", "charge"])
  );

  return {
    claim_number,
    payer,
    procedure_code,
    amount_billed
  };
}

// normalize ANY contract row correctly
function mapContractUploadRow(row){
  const payer = pickFirst(row, [
    "payer_name", "payer", "insurance", "insurance_name",
    "carrier", "plan", "plan_name"
  ]);

  const procedure_code = pickFirst(row, [
    "procedure_code", "cpt", "cpt_code",
    "proc_code", "hcpcs", "code",
    "service_code", "billing_code"
  ]);

  const diagnosis_code = pickFirst(row, [
    "diagnosis_code", "dx", "dx_code",
    "icd10", "icd10_code"
  ]);

  const effective_date_raw = pickFirst(row, [
    "effective_date", "effective", "contract_effective_date"
  ]);
  const effective_date = effective_date_raw
    ? new Date(effective_date_raw).toISOString().split("T")[0]
    : "";

  const network_status = pickFirst(row, [
    "network_status", "network", "in_network", "participation_status"
  ]) || "In Network";

  const reimbursement_model = pickFirst(row, [
    "reimbursement_model", "model", "payment_model"
  ]) || "fixed_amount";

  const expected_raw = pickFirst(row, [
    "allowed_amount", "expected_value", "expected",
    "rate", "amount", "fee"
  ]);

  return normalizeContract({
    payer_name: payer,
    procedure_code,
    diagnosis_code,
    effective_date,
    network_status,
    reimbursement_model,
    expected_value: num(expected_raw)
  });
}

// TRUE CONTRACT KEY (NOT claim matcher)
function contractRowKey(c){
  return [
    normalizeContractText(c.payer_name || c.payer || ""),
    getContractProcedureCode(c),
    normalizeCode(c.diagnosis_code || ""),
    String(c.effective_date || "").trim(),
    normalizeNetworkStatus(c.network_status || "In Network")
  ].join("|");
}

function detectFlexibleContractRow(row){
  if (!row || typeof row !== "object") return false;

  const keys = Object.keys(row).map(k => String(k).toLowerCase());

  const hasPayer = keys.some(k =>
    /(payer|insurance|carrier|plan)/i.test(k)
  );

  const hasProcedure = keys.some(k =>
    /(cpt|procedure|proc|hcpcs|code|service)/i.test(k)
  );

  const hasRate = keys.some(k =>
    /(allowed|expected|rate|amount|fee)/i.test(k)
  );

  return hasPayer && hasProcedure && hasRate;
}

function detectReimbursementUploadTypeFlexible(file, parsed){
  const rows = parsed?.rows || [];

  if (!rows.length) return "unknown";

  // NEW FLEXIBLE DETECTION
  if (detectFlexibleContractRow(rows[0])) {
    return "contract";
  }

  // fallback (existing logic)
  const first = rows[0];

  if (first.procedure_code && first.amount) return "fee_schedule";

  return "unknown";
}

function extractTextFromBuffer(buffer, filename){
  const ext = String(filename || "").toLowerCase();

  try {
    if (ext.endsWith(".pdf")) {
      // lightweight fallback (no external lib)
      return buffer.toString("utf8");
    }

    if (ext.endsWith(".doc") || ext.endsWith(".docx")) {
      return buffer.toString("utf8");
    }
  } catch (e){
    console.error("Document parse error:", e);
  }

  return "";
}

function extractContractSignalsFromText(text){
  const src = String(text || "");
  const compact = src.replace(/\r/g, "\n");
  const lines = compact.split("\n").map(x => x.trim()).filter(Boolean);

  const payerPattern = /\b(aetna|cigna|bcbs|blue\s*cross(?:\s*blue\s*shield)?|anthem|united(?:\s*healthcare)?|uhc|humana|medicare|medicaid|tricare|kaiser)\b/i;
  const cptPattern = /\b\d{5}\b/g;
  const amountPattern = /\$?\d{1,3}(?:,\d{3})*(?:\.\d{1,2})?/g;

  const detectedPayers = [];
  for (const line of lines) {
    const payerMatch = line.match(payerPattern);
    if (payerMatch && payerMatch[0]) detectedPayers.push(String(payerMatch[0]).trim());
  }
  const fallbackPayer = detectedPayers[0] || "";

  const rows = [];
  for (const line of lines) {
    const cpts = Array.from(line.matchAll(cptPattern)).map(m => m[0]);
    const amounts = Array.from(line.matchAll(amountPattern))
      .map(m => m[0])
      .map(v => num(String(v).replace(/\$/g, "").replace(/,/g, "")))
      .filter(v => v > 0);
    if (!cpts.length || !amounts.length) continue;

    const payerMatch = line.match(payerPattern);
    const payerName = payerMatch ? String(payerMatch[0]).trim() : fallbackPayer;
    if (!payerName) continue;

    for (const cpt of cpts) {
      rows.push({ payer_name: payerName, procedure_code: cpt, expected_value: amounts[0] });
    }
  }

  // File-level fallback: pair discovered CPTs with discovered amounts + payer.
  if (!rows.length && fallbackPayer) {
    const allCpts = Array.from(compact.matchAll(cptPattern)).map(m => m[0]);
    const allAmounts = Array.from(compact.matchAll(amountPattern))
      .map(m => num(String(m[0]).replace(/\$/g, "").replace(/,/g, "")))
      .filter(v => v > 0);
    const limit = Math.min(allCpts.length, allAmounts.length);
    for (let i = 0; i < limit; i++) {
      rows.push({ payer_name: fallbackPayer, procedure_code: allCpts[i], expected_value: allAmounts[i] });
    }
  }

  return rows;
}

function parseContractFromText(text){
  if (!text) return [];
  const extracted = extractContractSignalsFromText(text);
  const dedup = new Map();

  for (const row of extracted){
    const normalized = normalizeContract({
      payer_name: row.payer_name,
      procedure_code: row.procedure_code,
      expected_value: row.expected_value,
      network_status: "In Network",
      reimbursement_model: "fixed_amount"
    });
    const key = contractRowKey(normalized);
    if (!dedup.has(key)) dedup.set(key, normalized);
  }

  return Array.from(dedup.values());
}

