function detectFileType(filename){
  const ext = path.extname(String(filename || "").toLowerCase());
  if (ext === ".csv") return "CSV";
  if (ext === ".xls" || ext === ".xlsx") return "XLSX";
  if (ext === ".pdf") return "PDF";
  if (ext === ".txt") return "TXT-835";
  if (ext === ".doc" || ext === ".docx") return "DOC";
  if (ext === ".jpg" || ext === ".jpeg" || ext === ".png") return "IMAGE";
  return "UNKNOWN";
}

function categoryFromTab(tab){
  const t = String(tab || "claims").toLowerCase();
  if (["claims","payments","denials","contracts"].includes(t)) return t;
  if (t === "fee-schedules") return "fee_schedule";
  return "claims";
}

function isSupportedUploadExt(filename){
  const ext = path.extname(String(filename || "").toLowerCase());
  return [".csv", ".xls", ".xlsx", ".pdf", ".txt", ".doc", ".docx", ".jpg", ".jpeg", ".png"].includes(ext);
}

function addDocumentIngest(org_id, category, file, status, linkedCount=0, notes=""){
  const ingestCat = String(category || "claims").toLowerCase();
  const safeName = (file.filename || "document").replace(/[^a-zA-Z0-9._-]/g, "_");
  const dir = path.join(UPLOADS_DIR, org_id, ingestCat);
  ensureDir(dir);
  const storedPath = path.join(dir, `${Date.now()}_${safeName}`);
  fs.writeFileSync(storedPath, file.buffer);
  const ingests = readJSON(FILES.document_ingests, []);
  const rec = {
    ingest_id: uuid(),
    org_id,
    category: ingestCat,
    original_filename: safeName,
    stored_path: storedPath,
    uploaded_at: nowISO(),
    status: status || "Stored",
    detected_type: detectFileType(safeName),
    linked_claims_count: Number(linkedCount || 0),
    notes: String(notes || "")
  };
  ingests.push(rec);
  writeJSON(FILES.document_ingests, ingests);
  return rec;
}

function getAllowedAmountRules(org_id){
  const legacyAll = readJSON(FILES.allowed_amount_rules, []);
  const legacy = legacyAll.find(r => r.org_id === org_id);
  const settings = getOrgSettings(org_id);
  const fromSettings = getAllowedRulesFromSettings(settings);
  const defaults = {
    org_id,
    default_method: "percent_billed",
    default_value: 65,
    ucr_multiplier: 1,
    tolerance_percent: 1,
    tolerance_min_dollars: 5,
    payer_overrides: [],
    cpt_overrides: []
  };
  const hasSettingsRules = !!(settings && settings.allowed_rules && typeof settings.allowed_rules === "object");
  const base = hasSettingsRules ? { ...defaults, ...fromSettings } : (legacy ? { ...defaults, ...legacy } : defaults);
  if (!Array.isArray(base.payer_overrides) && Array.isArray(legacy?.payer_overrides)) base.payer_overrides = legacy.payer_overrides;
  if (!Array.isArray(base.cpt_overrides) && Array.isArray(legacy?.cpt_overrides)) base.cpt_overrides = legacy.cpt_overrides;
  if (hasSettingsRules && !Array.isArray(fromSettings.payer_overrides) && Array.isArray(legacy?.payer_overrides)) base.payer_overrides = legacy.payer_overrides;
  if (hasSettingsRules && !Array.isArray(fromSettings.cpt_overrides) && Array.isArray(legacy?.cpt_overrides)) base.cpt_overrides = legacy.cpt_overrides;
  return { ...base, org_id };
}

function saveAllowedAmountRules(org_id, rules){
  const current = getAllowedAmountRules(org_id);
  const mergedRules = { ...current, ...(rules || {}), org_id };
  if (!Array.isArray(mergedRules.payer_overrides)) mergedRules.payer_overrides = [];
  if (!Array.isArray(mergedRules.cpt_overrides)) mergedRules.cpt_overrides = [];
  const settings = getOrgSettings(org_id);
  saveOrgSettings(org_id, { allowed_rules: { ...(settings.allowed_rules || {}), ...mergedRules } });
  const all = readJSON(FILES.allowed_amount_rules, []);
  const keep = all.filter(r => r.org_id !== org_id);
  writeJSON(FILES.allowed_amount_rules, keep.concat([{ ...mergedRules, org_id, updated_at: nowISO() }]));
}

function getFeeSchedules(org_id){
  return readJSON(FILES.fee_schedules, []).filter(x => x.org_id === org_id);
}

function saveFeeSchedules(org_id, schedules){
  const all = readJSON(FILES.fee_schedules, []);
  const keep = all.filter(x => x.org_id !== org_id);
  writeJSON(FILES.fee_schedules, keep.concat((schedules || []).map(s => ({ ...s, org_id }))));
}

function lookupFeeScheduleAmount(org_id, claim){
  const schedules = getFeeSchedules(org_id);
  const proc = getClaimProcedureCode(claim);
  const payer = String(claim.payer || "").trim().toLowerCase();
  for (const sch of schedules) {
    const rows = Array.isArray(sch.rows) ? sch.rows : [];
    const m = rows.find(r => normalizeCode(r.procedure_code) === proc && (!sch.payer_name || String(sch.payer_name || "").trim().toLowerCase() === payer));
    if (m) return num(m.amount);
  }
  return 0;
}

function computeExpectedInsuranceForClaim(claim){
  const billed = num(claim.amount_billed);
  const patientResp = num(claim.patient_responsibility);
  const contract = claim?.org_id ? findContractForClaim(claim.org_id, claim) : null;
  if (contract) {
    const expectedAmount = contractExpectedAmount(contract, billed);
    return {
      amount: Math.max(0, num(expectedAmount) - patientResp),
      source: "contract",
      contract_id: contract.contract_id || "",
      network_status: String(contract.network_status || "Unknown")
    };
  }
  const rules = getAllowedAmountRules(claim.org_id || "");
  const payer = String(claim.payer || "").trim().toLowerCase();
  const cpt = getClaimProcedureCode(claim);
  const payerOv = (rules.payer_overrides || []).find(x => String(x.payer_name || "").trim().toLowerCase() === payer);
  const cptOv = (rules.cpt_overrides || []).find(x => normalizeCode(x.procedure_code) === cpt);
  const method = String(cptOv?.method || payerOv?.method || rules.default_method || "percent_billed");
  const value = num(cptOv?.value != null ? cptOv.value : (payerOv?.value != null ? payerOv.value : rules.default_value));
  const ucr = num(rules.ucr_multiplier || 1) || 1;
  const feeAmount = lookupFeeScheduleAmount(claim.org_id || "", claim);
  const medicareRate = num(claim.medicare_rate || feeAmount);
  let allowed = billed;
  if (method === "fee_schedule" && feeAmount > 0) allowed = feeAmount;
  else if (feeAmount > 0 && method === "ucr_multiplier") allowed = feeAmount * ucr;
  else if (method === "percent_medicare") allowed = medicareRate * (value / 100);
  else if (method === "percent_billed") allowed = billed * (value / 100);
  else if (method === "fixed_fee" || method === "flat") allowed = value;
  else if (method === "ucr_multiplier") allowed = billed * ucr;
  return {
    amount: Math.max(0, allowed - patientResp),
    source: "rules"
  };
}

function getClaimBatches(org_id){
  return readJSON(FILES.claim_batches, []).filter(x => x.org_id === org_id);
}

function saveClaimBatches(org_id, batches){
  const all = readJSON(FILES.claim_batches, []);
  const keep = all.filter(x => x.org_id !== org_id);
  writeJSON(FILES.claim_batches, keep.concat((batches || []).map(x => ({ ...x, org_id }))));
}

function normalizeCode(v){
  return String(v || "").trim().toUpperCase();
}

function normalizeClaimKey(v){
  return String(v || "").replace(/[^0-9]/g, "");
}

function buildClaimContext(org_id){
  const payments = readJSON(FILES.payments, []).filter(p => p.org_id === org_id);
  const cases = readJSON(FILES.cases, []).filter(c => c.org_id === org_id);
  const negotiations = getNegotiations(org_id).map(n => normalizeNegotiation(n));
  const paymentsByClaim = {};
  payments.forEach(p => {
    const k = normalizeClaimKey(p.claim_number || "");
    if (!k) return;
    if (!paymentsByClaim[k]) paymentsByClaim[k] = [];
    paymentsByClaim[k].push(p);
  });
  const caseById = new Map(cases.map(c => [String(c.case_id), c]));
  const negByBilled = new Map(negotiations.map(n => [String(n.billed_id || ""), n]));
  return { paymentsByClaim, caseById, negByBilled };
}

function ensureDenialCaseForClaim(claim){
  if (!claim || claim.denial_case_id) return;
  if (!claim.org_id || !claim.billed_id) return;

  const billedAll = readJSON(FILES.billed, []);
  const billedIdx = billedAll.findIndex(b => String(b.billed_id || "") === String(claim.billed_id || ""));
  if (billedIdx < 0) return;

  if (billedAll[billedIdx].denial_case_id) {
    claim.denial_case_id = billedAll[billedIdx].denial_case_id;
    return;
  }

  const cases = readJSON(FILES.cases, []);
  const existingCase = cases.find(c =>
    c.type === "denial" &&
    String(c.org_id || "") === String(claim.org_id || "") &&
    String(c.billed_id || "") === String(claim.billed_id || "")
  );

  if (existingCase) {
    claim.denial_case_id = existingCase.case_id;
    billedAll[billedIdx].denial_case_id = existingCase.case_id;
    writeJSON(FILES.billed, billedAll);
    return;
  }

  const newCase = {
    case_id: uuid(),
    type: "denial",
    status: "Open",
    org_id: claim.org_id,
    billed_id: claim.billed_id,
    created_at: nowISO(),
    stage: "Drafted",
  };
  cases.push(newCase);
  writeJSON(FILES.cases, cases);

  claim.denial_case_id = newCase.case_id;
  billedAll[billedIdx].denial_case_id = newCase.case_id;
  writeJSON(FILES.billed, billedAll);
}

function evaluateClaimDerived(claim, ctx={}){
  const claimCtx = (ctx && ctx.paymentsByClaim) ? ctx : buildClaimContext(claim.org_id || "");
  const billedAmount = num(claim.amount_billed);
  const allowedAmount = num(claim.allowed_amount);
  const patient = computePatientBalance(claim);
  const insurance = computeInsuranceBalance(claim, claimCtx);
  const expectedInsurance = insurance.expectedInsurance;
  const paidAmount = insurance.paidAmount;
  const insuranceWriteOff = insurance.insuranceWriteOff;
  const insuranceRemaining = insurance.insuranceRemaining;
  // expectedInsurance is null when no contract rule exists (UI should show "-")
  // but lifecycle + risk math still needs a fallback to avoid "0 expected" breaking denials.
  const expectedForLifecycle = (expectedInsurance !== null && expectedInsurance !== undefined)
    ? Number(expectedInsurance)
    : Number(billedAmount || 0);

  const remainingForLifecycle = (insuranceRemaining !== null && insuranceRemaining !== undefined)
    ? Number(insuranceRemaining)
    : Math.max(0, expectedForLifecycle - Number(paidAmount || 0) - Number(insuranceWriteOff || 0));
  const patientWriteOff = patient.patientWriteOff;
  const patientBalanceRemaining = patient.patientBalanceRemaining;

  const key = normalizeClaimKey(claim.claim_number || "");
  const paymentRows = key && claimCtx.paymentsByClaim ? (claimCtx.paymentsByClaim[key] || []) : [];
  const paidFieldAmount = Math.max(
    num(claim.insurance_paid || 0),
    num(claim.paid_amount || 0)
  );
  const hasPositivePaidField = paidFieldAmount > 0.0001;
  const submittedFlag = !!(claim.submission_id || claim.submitted_at || claim.submitted_date || claim.submitted_to_payer);

  const appealCase = claim.denial_case_id && claimCtx.caseById ? claimCtx.caseById.get(String(claim.denial_case_id)) : null;
  const negotiation = claimCtx.negByBilled ? claimCtx.negByBilled.get(String(claim.billed_id || "")) : null;
  const activeCaseStatuses = ["Drafted", "Submitted", "In Review", "Counter Offered", "Approved (Pending Payment)"];
  const appealStatus = String(appealCase?.status || "");
  const negotiationStatus = String(negotiation?.status || "");
  const hasActiveAppealOrNegotiation = activeCaseStatuses.includes(appealStatus) || activeCaseStatuses.includes(negotiationStatus);

  const denialReason = String(
    claim.denial_reason ||
    claim.denial_code ||
    appealCase?.denial_reason ||
    appealCase?.issue_reason ||
    ""
  ).trim();
  const denialDocAttached = !!(
    claim.denial_doc_attached ||
    claim.denial_document ||
    claim.denial_file ||
    (appealCase && (((appealCase.files || []).length > 0) || ((appealCase.appeal_attachments || []).length > 0)))
  );
  const explicitDenialUpload =
    denialDocAttached ||
    String(appealCase?.status || "").toLowerCase().includes("denied") ||
    String(claim.denial_status || "").toLowerCase().includes("denied");
  const hasDenialContext = !!(denialReason || denialDocAttached || appealCase || explicitDenialUpload);
  const responseStatus = String(
    claim.remittance_status ||
    claim.payment_status ||
    claim.eob_status ||
    claim.denial_status ||
    ""
  ).trim();
  const hasPaymentRecord =
    paymentRows.length > 0 ||
    hasPositivePaidField ||
    !!claim.paid_at ||
    !!hasDenialContext ||
    !!responseStatus;

  const expectedAmount = expectedForLifecycle;

  let lifecycleStage = "Paid";
  if (hasActiveAppealOrNegotiation) {
    lifecycleStage = "In Appeal/Negotiation";
  } else if (submittedFlag && !hasPaymentRecord) {
    lifecycleStage = "Waiting Payment";
  } else if (hasPaymentRecord && paidAmount <= 0.0001 && expectedAmount > 0) {
    lifecycleStage = "Denied";
    const settings = getPracticeSettings(claim.org_id);
    if (settings.auto_create_denial_cases === true) ensureDenialCaseForClaim(claim);
  } else if (hasPaymentRecord && paidAmount > 0 && paidAmount + 0.0001 < expectedAmount) {
    lifecycleStage = "Underpaid";
  } else if (remainingForLifecycle <= 0.0001 && patientBalanceRemaining > 0.0001) {
    lifecycleStage = "Patient Follow-Up";
  } else if (remainingForLifecycle <= 0.0001 && patientBalanceRemaining <= 0.0001) {
    lifecycleStage = "Resolved";
  } else if (!submittedFlag) {
    lifecycleStage = "Submitted";
  } else {
    lifecycleStage = "Waiting Payment";
  }

  let atRiskAmount = 0;
  if (lifecycleStage === "Denied") atRiskAmount = Math.max(0, expectedForLifecycle - paidAmount);
  else if (lifecycleStage === "Underpaid") atRiskAmount = Math.max(0, remainingForLifecycle);
  else if (lifecycleStage === "Waiting Payment" || lifecycleStage === "Submitted") atRiskAmount = Math.max(0, expectedForLifecycle - paidAmount);
  else if (lifecycleStage === "Patient Follow-Up") atRiskAmount = patientBalanceRemaining;
  else if (lifecycleStage === "In Appeal/Negotiation") atRiskAmount = Math.max(0, remainingForLifecycle) + patientBalanceRemaining;

  return {
    lifecycleStage,
    financialStatus: lifecycleStage,
    expectedInsurance,
    paidAmount,
    billedAmount,
    allowedAmount,
    underpaidAmount: Math.max(0, remainingForLifecycle),
    patientBalanceRemaining,
    insuranceWriteOff,
    patientWriteOff,
    atRiskAmount: Math.max(0, atRiskAmount),
    writeOffAmount: Math.max(0, insuranceWriteOff),
    submittedFlag,
    hasPaymentResponse: hasPaymentRecord,
    hasDenialContext
  };
}

function computePatientBalance(claim){
  const patientResp = num(claim.patient_responsibility || 0);
  const patientCollected = num(claim.patient_collected || 0);
  const patientWriteOff = num(claim.patient_writeoff_amount || 0);
  const patientBalanceRemaining = Math.max(0, patientResp - patientCollected - patientWriteOff);
  return { patientResp, patientCollected, patientWriteOff, patientBalanceRemaining };
}

function computeInsuranceBalance(claim, ctx={}){
  const claimCtx = (ctx && ctx.paymentsByClaim) ? ctx : buildClaimContext(claim.org_id || "");
  const expectedInsuranceRaw = computeExpectedInsuranceForClaim(claim);
  const hasContract = Boolean(expectedInsuranceRaw && expectedInsuranceRaw.source === "contract");
  const expectedInsurance = hasContract ? num(expectedInsuranceRaw.amount) : null;
  const key = normalizeClaimKey(claim.claim_number || "");
  const paymentRows = key && claimCtx.paymentsByClaim ? (claimCtx.paymentsByClaim[key] || []) : [];
  const paymentFromRows = paymentRows.reduce((s, p) => s + num(p.amount_paid), 0);
  const paidFromClaim = num(claim.insurance_paid || claim.paid_amount);
  const paidAmount = Math.max(paymentFromRows, paidFromClaim);
  const insuranceWriteOff = num(claim.write_off_amount || claim.contractual_adjustment || claim.write_off || 0);
  const insuranceRemaining =
    expectedInsurance !== null
      ? Math.max(0, expectedInsurance - paidAmount - insuranceWriteOff)
      : null;
  return { expectedInsurance, paidAmount, insuranceWriteOff, insuranceRemaining };
}

function computeClaimFinancials(claim){
  const insurance = computeInsuranceBalance(claim);
  return {
    expectedInsurance: insurance.expectedInsurance !== null
      ? Number(insurance.expectedInsurance)
      : null,
    paidInsurance: Number(insurance.paidAmount || 0),
    insuranceRemaining: insurance.insuranceRemaining !== null
      ? Number(insurance.insuranceRemaining)
      : null,
    insuranceWriteOff: Number(insurance.insuranceWriteOff || 0)
  };
}

function isResolvedLifecycleStage(stage){
  const s = String(stage || "").trim();
  return ["Resolved", "Write-Off", "Revenue Collected", "Closed", "Contractual"].includes(s);
}

function computeExecutiveRevenueMetrics(org_id){
  const claims = readJSON(FILES.billed, []).filter(b => b.org_id === org_id);
  const claimCtx = buildClaimContext(org_id);
  return claims.reduce((acc, claim) => {
    const d = evaluateClaimDerived(claim, claimCtx);
    const billed = num(claim.amount_billed);
    const paid = num(d.paidAmount);
    const expectedInsurance = num(d.expectedInsurance);
    acc.totalBilled += billed;
    acc.totalCollected += paid + num(claim.patient_collected);
    if (!isResolvedLifecycleStage(d.lifecycleStage)) {
      acc.totalAtRisk += Math.max(0, d.underpaidAmount) + Math.max(0, d.patientBalanceRemaining);
    }
    return acc;
  }, { totalBilled: 0, totalCollected: 0, totalAtRisk: 0 });
}

// =============================
// PRACTICE FINANCIAL HEALTH ENGINE
// =============================
function scoreCollectionRate(rate){
  if (rate >= 85) return 100;
  if (rate >= 75) return 85;
  if (rate >= 65) return 70;
  if (rate >= 55) return 55;
  return 40;
}

function scoreDenialRate(rate){
  if (rate <= 5) return 100;
  if (rate <= 10) return 85;
  if (rate <= 15) return 70;
  if (rate <= 20) return 55;
  return 40;
}

function scoreUnderpaidRate(rate){
  if (rate <= 5) return 100;
  if (rate <= 10) return 85;
  if (rate <= 15) return 70;
  if (rate <= 20) return 55;
  return 40;
}

function scoreDaysToPay(days){
  if (days <= 20) return 100;
  if (days <= 30) return 85;
  if (days <= 45) return 70;
  if (days <= 60) return 55;
  return 40;
}

function scoreARAging(rate){
  if (rate <= 10) return 100;
  if (rate <= 20) return 85;
  if (rate <= 30) return 70;
  if (rate <= 40) return 55;
  return 40;
}

function scoreOperationalDiscipline(rate){
  // rate = % of AI workspaces with required docs present (by channel) among "ready/submitted/closed"
  if (rate >= 90) return 100;
  if (rate >= 75) return 85;
  if (rate >= 60) return 70;
  if (rate >= 40) return 55;
  return 40;
}

function clampPct(n){
  const v = Number(n || 0);
  if (!isFinite(v)) return 0;
  return Math.max(0, Math.min(100, v));
}

function gradeFromScore(score){
  if (score >= 90) return "A";
  if (score >= 80) return "B";
  if (score >= 70) return "C";
  if (score >= 60) return "D";
  return "F";
}

function findContractForClaim(org_id, b){

  const claim = stampCanonicalClaimFields({ ...b });
  const contracts = getPayerContracts(org_id).map(normalizeContract);

  // 🔥 DEBUG ONLY FOR PROBLEM CLAIM
  debugClaimAndContracts(org_id, claim, contracts);

  let best = null;

  for (const c of contracts){
    if (!contractMatchesClaim(c, claim)) continue;

    best = c;
    break; // first match wins (for now)
  }

  return best || null;
}
function contractExpectedAmount(contract, billedAmount){
  if (!contract) return null;
  const model = String(contract.reimbursement_model || "fixed_amount");
  const value = num(contract.expected_value);
  const billed = num(billedAmount);
  if (model === "percent_of_charge") return billed * (value / 100);
  if (model === "percent_of_medicare") return billed * (value / 100);
  return value;
}

function classifyClaimStatusWithContract(claim){
  const d = evaluateClaimDerived(claim, {});
  return String(d.lifecycleStage || claim.status || "Waiting Payment");
}

function recalculateContractsForOrg(org_id){
  const billedAll = readJSON(FILES.billed, []);
  let changed = false;
  for (const b of billedAll) {
    if (b.org_id !== org_id) continue;
    stampCanonicalClaimFields(b);
    const contracts = getPayerContracts(org_id).map(normalizeContract);
    const contract = findContractForClaim(org_id, b);

    debugLog("Claim processed:", {
      claim: b.claim_number,
      payer: b.payer,
      claim_payer_raw: b.claim_payer_raw,
      claim_procedure_code_raw: b.claim_procedure_code_raw,
      claim_diagnosis_code_raw: b.claim_diagnosis_code_raw,
      rawProcedure: b.procedure_code,
      rawCpt: b.cpt_code,
      rawCode: b.code,
      rawHcpcs: b.hcpcs,
      rawServiceCode: b.service_code,
      rawBillingCode: b.billing_code,
      rawPrimaryProcedure: b.primary_procedure,
      rawDx: b.diagnosis_code,
      rawIcd10: b.icd10,
      rawIcd10Code: b.icd10_code,
      rawDxCode: b.dx_code,
      canonicalPayer: b.claim_payer_normalized,
      canonicalCpt: b.claim_procedure_code_normalized,
      canonicalDx: b.claim_diagnosis_code_normalized,
      finalCpt: getClaimProcedureCode(b),
      finalDx: getClaimDiagnosisCode(b),
      matchedContract: contract?.contract_id || null
    });
    debugLog("Contract candidates evaluated:", {
      claim_number: b?.claim_number,
      count: contracts.length
    });

    if (!contract) {
      b.expected_insurance = "";
      b.underpaid_amount = 0;
      b.network_status = "Unknown";
      b.contract_applied = false;
      b.contract_rule_id = "";
      b.contract_expected_amount = 0;
      b.contract_expected_value = 0;
      b.contract_reimbursement_model = "";
      changed = true;
      continue;
    }

    const billedAmt = num(b.amount_billed);
    const expectedAmount = num(contractExpectedAmount(contract, billedAmt));
    const expectedInsurance = Math.max(0, expectedAmount - num(b.patient_responsibility));

    const paid = num(b.insurance_paid || b.paid_amount);
    const underpaid = Math.max(0, expectedInsurance - paid);

    b.network_status = String(contract.network_status || "Unknown");
    b.contract_applied = true;
    b.contract_rule_id = String(contract.contract_id || "");
    b.contract_reimbursement_model = contract.reimbursement_model;
    b.contract_expected_value = num(contract.expected_value);
    b.contract_expected_amount = expectedAmount;
    b.expected_insurance = expectedInsurance;
    b.underpaid_amount = underpaid;
    b.status = classifyClaimStatusWithContract(b);
    changed = true;
  }
  if (changed) {
    writeJSON(FILES.billed, billedAll);
  }
}

function backfillCanonicalClaimFieldsForOrg(org_id){
  const billedAll = readJSON(FILES.billed, []);
  let changed = false;

  for (const b of billedAll) {
    if (b.org_id !== org_id) continue;

    const beforePayer = b.claim_payer_normalized || "";
    const beforeProc = b.claim_procedure_code_normalized || "";
    const beforeDx = b.claim_diagnosis_code_normalized || "";

    stampCanonicalClaimFields(b);

    if (
      beforePayer !== (b.claim_payer_normalized || "") ||
      beforeProc !== (b.claim_procedure_code_normalized || "") ||
      beforeDx !== (b.claim_diagnosis_code_normalized || "")
    ) {
      changed = true;
    }
  }

  if (changed) writeJSON(FILES.billed, billedAll);
}

function getClaimBatchHistory(org_id){
  return readJSON(FILES.upload_batches, [])
    .filter(b => b.org_id === org_id)
    .map(b => ({
      upload_id: String(b.upload_id || ""),
      filename: b.file_name || "batch",
      uploaded_at: b.uploaded_at,
      uploaded_by: b.uploaded_by || "",
      claim_count: num(b.claim_count),
      total_billed: num(b.total_billed),
    }))
    .sort((a, b) => new Date(b.uploaded_at || 0).getTime() - new Date(a.uploaded_at || 0).getTime());
}

function getPaymentBatchHistory(org_id){
  const payments = readJSON(FILES.payments, []).filter(p => p.org_id === org_id);
  const map = {};
  for (const p of payments) {
    const source = String(p.source_file || "manual").trim() || "manual";
    if (!map[source]) map[source] = { source_file: source, row_count: 0, total_paid: 0, uploaded_at: p.created_at || p.date_paid || nowISO() };
    map[source].row_count += 1;
    map[source].total_paid += num(p.amount_paid);
    const dt = new Date(p.created_at || p.date_paid || 0).getTime();
    if (dt > new Date(map[source].uploaded_at || 0).getTime()) map[source].uploaded_at = p.created_at || p.date_paid || map[source].uploaded_at;
  }
  return Object.values(map).sort((a, b) => new Date(b.uploaded_at || 0).getTime() - new Date(a.uploaded_at || 0).getTime());
}

function getUnmatchedPayments(org_id, billed){
  const payments = readJSON(FILES.payments, []).filter(p => p.org_id === org_id);
  return payments.filter(p => !findBilledByClaim(org_id, billed, p.claim_number));
}

function runAIRecoveryEngine(org_id){
  if (!org_id) return;
  const billedAll = readJSON(FILES.billed, []);
  const ctx = buildClaimContext(org_id);

  for (const claim of billedAll) {
    if (claim.org_id !== org_id) continue;
    const d = evaluateClaimDerived(claim, ctx);

    if (d.lifecycleStage === "Denied") {
      const ws = ensureAgentWorkspace(org_id, claim);
      if (ws.appeal?.auto_generated || shouldLockPacket(ws, "appeal")) continue;
      if (!ws.appeal || !ws.appeal.draft_text) {
        autoDraftWorkspaceForClaim(org_id, claim, d, ctx);
        const wsUpdated = ensureAgentWorkspace(org_id, claim);
        wsUpdated.appeal = wsUpdated.appeal || {};
        wsUpdated.appeal.auto_generated = true;
        wsUpdated.appeal.generated_at = nowISO();
        if (!wsUpdated.appeal.strategy_profile || wsUpdated.appeal.strategy_profile === "Auto") {
          wsUpdated.appeal.strategy_profile = "Regulatory";
        }
        saveAgentWorkspace(org_id, wsUpdated);
        addAgentMessage(org_id, {
          message_id: uuid(),
          workspace_id: wsUpdated.workspace_id,
          billed_id: claim.billed_id,
          role: "agent",
          channel: "appeal",
          content: "AI automatically generated appeal packet based on denial detection.",
          created_at: nowISO()
        });
      }
    }

    if (d.lifecycleStage === "Underpaid") {
      const ws = ensureAgentWorkspace(org_id, claim);
      if (ws.negotiation?.auto_generated || shouldLockPacket(ws, "negotiation")) continue;
      if (!ws.negotiation || !ws.negotiation.draft_text) {
        autoDraftWorkspaceForClaim(org_id, claim, d, ctx);
        const wsUpdated = ensureAgentWorkspace(org_id, claim);
        wsUpdated.negotiation = wsUpdated.negotiation || {};
        wsUpdated.negotiation.auto_generated = true;
        wsUpdated.negotiation.generated_at = nowISO();
        wsUpdated.negotiation.packet_sections = wsUpdated.negotiation.packet_sections || defaultNegotiationPacketSections();
        if (!wsUpdated.negotiation.packet_sections.requested_amount) {
          wsUpdated.negotiation.packet_sections.requested_amount = String(Number(d.underpaidAmount || 0));
        }
        if (!wsUpdated.negotiation.strategy_profile || wsUpdated.negotiation.strategy_profile === "Auto") {
          wsUpdated.negotiation.strategy_profile = "Contractual";
        }
        saveAgentWorkspace(org_id, wsUpdated);
        addAgentMessage(org_id, {
          message_id: uuid(),
          workspace_id: wsUpdated.workspace_id,
          billed_id: claim.billed_id,
          role: "agent",
          channel: "negotiation",
          content: "AI automatically generated negotiation packet based on underpayment detection.",
          created_at: nowISO()
        });
      }
    }
  }
}

function rebuildOrgDerivedData(org_id, opts={}){
  const settings = { resyncDenials: false, autodraft: false, ...opts };
  recalculateContractsForOrg(org_id);
  const billedAll = readJSON(FILES.billed, []);
  const ctx = buildClaimContext(org_id);
  let changed = false;
  for (const b of billedAll) {
    if (b.org_id !== org_id) continue;
    const d = evaluateClaimDerived(b, ctx);
    b.expected_insurance = (d.expectedInsurance == null) ? "" : num(d.expectedInsurance);
    b.underpaid_amount = Math.max(0, num(d.underpaidAmount));
    b.lifecycle_stage = d.lifecycleStage;
    b.status = d.lifecycleStage;
    if (settings.autodraft && ["Denied","Underpaid"].includes(String(d.lifecycleStage || ""))) autoDraftWorkspaceForClaim(org_id, b, d, ctx);
    if (settings.resyncDenials && d.lifecycleStage === "Denied") ensureDenialCaseForClaim(b);
    changed = true;
  }
  if (changed) writeJSON(FILES.billed, billedAll);
  runAIRecoveryEngine(org_id);
  enqueueRecoveryTasksForOrg(org_id);
  runRecoveryAgentTick(org_id);
  runClaimAutomationSweep(org_id);

  const subsAll = readJSON(FILES.billed_submissions, []);
  const orgClaims = billedAll.filter(b => b.org_id === org_id);
  for (const s of subsAll) {
    if (s.org_id !== org_id) continue;
    const claims = orgClaims.filter(c => String(c.submission_id || "") === String(s.submission_id || ""));
    const totals = claims.reduce((acc, c) => {
      const d = evaluateClaimDerived(c, ctx);
      acc.billed += num(c.amount_billed);
      acc.paid += num(d.paidAmount);
      acc.expected += num(d.expectedInsurance);
      return acc;
    }, { billed: 0, paid: 0, expected: 0 });
    s.claim_count = claims.length;
    s.total_billed = totals.billed;
    s.total_paid = totals.paid;
    s.total_expected_insurance = totals.expected;
    s.updated_at = nowISO();
  }
  writeJSON(FILES.billed_submissions, subsAll);
}

function getClaimAgingStartDate(claim){
  const candidates = [
    claim.submitted_at,
    claim.submitted_date,
    claim.created_at,
    claim.dos
  ];
  for (const raw of candidates){
    const t = new Date(raw || 0).getTime();
    if (Number.isFinite(t) && t > 0) return t;
  }
  return Date.now();
}

function getClaimAgeDays(claim){
  const start = getClaimAgingStartDate(claim);
  return Math.max(0, Math.floor((Date.now() - start) / (1000 * 60 * 60 * 24)));
}

function normalizeAutomationLifecycleStage(stage){
  const s = String(stage || "").trim();
  if (s === "Submitted" || s === "Waiting Payment") return "Awaiting Payment";
  return s || "Pending";
}

function getClaimAutomationNextAction(stage, ageDays, derived){
  const s = normalizeAutomationLifecycleStage(stage);
  if (s === "Denied") return "Appeal";
  if (s === "Underpaid") return "Negotiate";
  if (s === "In Appeal/Negotiation") return "Review Workspace";
  if (s === "Patient Follow-Up") return "Collect Patient Balance";
  if (s === "Awaiting Payment" && ageDays >= 21) return "Follow Up With Payer";
  if (s === "Awaiting Payment") return "Monitor Payer Response";
  if (isResolvedLifecycleStage(s)) return "Resolved";
  if (Number(derived?.atRiskAmount || 0) > 0) return "Review Claim";
  return "Monitor Claim";
}

function ensureAgingFollowupTask(org_id, claim, derived, ageDays){
  if (!org_id || !claim?.billed_id) return null;

  const stage = normalizeAutomationLifecycleStage(derived?.lifecycleStage || claim?.status || "");
  if (stage !== "Awaiting Payment") return null;
  if (ageDays < 21) return null;

  const allTasks = readJSON(FILES.agent_tasks, []);
  const existing = allTasks.find(t =>
    t.org_id === org_id &&
    String(t.billed_id || "") === String(claim.billed_id || "") &&
    String(t.stage_type || "") === "followup" &&
    String(t.status || "") !== "closed"
  );

  const priority = Math.min(100, 55 + Math.floor(ageDays / 3) + Math.floor(num(derived?.atRiskAmount || 0) / 1000));
  const dueAt = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();

  if (existing) {
    return markTask(existing.task_id, {
      priority,
      status: "ready_for_review",
      risk_level: ageDays >= 30 ? "HIGH" : "MEDIUM",
      estimated_value: Number(num(derived?.atRiskAmount || 0)),
      recommended_next_step: "Follow up with payer for missing payment response",
      next_actions: [
        "Call payer",
        "Check claim status",
        "Document reference number",
        "Upload payment if received"
      ],
      notes: `Awaiting payment for ${ageDays} day(s).`,
      follow_up_due_at: dueAt
    });
  }

  return upsertAgentTask({
    org_id,
    billed_id: claim.billed_id,
    stage_type: "followup",
    status: "ready_for_review",
    priority,
    risk_level: ageDays >= 30 ? "HIGH" : "MEDIUM",
    estimated_value: Number(num(derived?.atRiskAmount || 0)),
    recommended_next_step: "Follow up with payer for missing payment response",
    next_actions: [
      "Call payer",
      "Check claim status",
      "Document reference number",
      "Upload payment if received"
    ],
    missing_docs: [],
    notes: `Awaiting payment for ${ageDays} day(s).`,
    follow_up_due_at: dueAt
  });
}

function runClaimAutomationSweep(org_id){
  if (!org_id) return { processed: 0, updated: 0, followups: 0 };

  const billedAll = readJSON(FILES.billed, []);
  const ctx = buildClaimContext(org_id);
  let updated = 0;
  let followups = 0;

  for (const claim of billedAll) {
    if (claim.org_id !== org_id) continue;

    const derived = evaluateClaimDerived(claim, ctx);
    const lifecycleStage = normalizeAutomationLifecycleStage(derived.lifecycleStage || claim.status || "");
    const ageDays = getClaimAgeDays(claim);
    const riskScore = computeClaimRiskScore(claim);
    const atRiskAmount = computeClaimAtRisk(claim);
    const nextAction = getClaimAutomationNextAction(lifecycleStage, ageDays, derived);

    const followupThresholdDays = lifecycleStage === "Awaiting Payment" ? 21 : 14;
    const needsFollowup =
      !isResolvedLifecycleStage(lifecycleStage) &&
      lifecycleStage !== "Denied" &&
      lifecycleStage !== "Underpaid" &&
      ageDays >= followupThresholdDays;

    const followupStatus =
      needsFollowup
        ? (ageDays >= 30 ? "Urgent Follow-Up" : "Follow-Up Needed")
        : "";

    const before = JSON.stringify({
      lifecycle_stage: claim.lifecycle_stage,
      status: claim.status,
      risk_score: claim.risk_score,
      at_risk_amount: claim.at_risk_amount,
      age_days: claim.age_days,
      next_action: claim.next_action,
      requires_follow_up: claim.requires_follow_up,
      follow_up_status: claim.follow_up_status
    });

    claim.lifecycle_stage = lifecycleStage;
    claim.status = lifecycleStage;
    claim.risk_score = riskScore;
    claim.at_risk_amount = Number(num(atRiskAmount));
    claim.age_days = ageDays;
    claim.next_action = nextAction;
    claim.requires_follow_up = !!needsFollowup;
    claim.follow_up_status = followupStatus;
    claim.follow_up_due_at = needsFollowup
      ? new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString()
      : "";
    claim.last_automation_run_at = nowISO();

    if (lifecycleStage === "Denied") {
      ensureDenialCaseForClaim(claim);
    }

    if (lifecycleStage === "Awaiting Payment" && needsFollowup) {
      const task = ensureAgingFollowupTask(org_id, claim, derived, ageDays);
      if (task) followups += 1;
    }

    const after = JSON.stringify({
      lifecycle_stage: claim.lifecycle_stage,
      status: claim.status,
      risk_score: claim.risk_score,
      at_risk_amount: claim.at_risk_amount,
      age_days: claim.age_days,
      next_action: claim.next_action,
      requires_follow_up: claim.requires_follow_up,
      follow_up_status: claim.follow_up_status
    });

    if (before !== after) updated += 1;
  }

  writeJSON(FILES.billed, billedAll);

  return {
    processed: billedAll.filter(b => b.org_id === org_id).length,
    updated,
    followups
  };
}

function runAutomationCycleForOrg(org_id){
  if (!org_id) return null;

  rebuildOrgDerivedData(org_id, {
    resyncDenials: true,
    autodraft: true
  });

  return runClaimAutomationSweep(org_id);
}

function runAutomationCycleForAllOrgs(){
  const orgs = readJSON(FILES.orgs, []);
  let cycles = 0;

  for (const org of orgs) {
    if (!org?.org_id) continue;
    if (String(org.account_status || "active") !== "active") continue;

    try {
      runAutomationCycleForOrg(org.org_id);
      cycles += 1;
    } catch (e) {
      console.error("Automation cycle error:", org.org_id, e?.message || e);
    }
  }

  return cycles;
}

